import type { LocalizedTutorialContent } from '../tutorials-longform-i18n';

// Localized long-form content for one tutorial. Generated from validated
// per-locale translation JSONs; en renders from the Markdown source.
export const entry: Partial<Record<string, LocalizedTutorialContent>> = {
  "zh": {
    title: "Open Design —— 一次诚实的初体验（Bug、修复与任意模型配置）",
    summary: "对 Open Design 的一次不加修饰的初体验——安装、配置任意 agent、实时构建一个真实原型（连同粗糙之处一并呈现）、使用画布上的编辑/检查/评论工具，并通过 OpenRouter 这类兼容 OpenAI 的服务商低成本接入任意模型。基于 Sasha（ИИШНЫЙ）的实操评测。",
    bodyHtml: "<p>本指南是对 Open Design 一次刻意诚实的初体验——既有开箱即用的部分，也有你会遇到的粗糙之处，全程实录而非剪辑掩盖。它还介绍了一个真正实用的技巧：通过兼容 OpenAI 的服务商，低成本接入<em>任意</em>模型。内容基于 <strong>Sasha（ИИШНЫЙ）</strong>在<a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">他的实操视频</a>中记录的动手评测，并针对本篇图文指南做了改编，同时更新到了当前版本。可观看上方视频看实时演示，或继续阅读图文版。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/workspace-home.webp\" alt=\"Open Design 工作区——描述你想要的内容并选择一个模式。\">\n<em>Open Design 工作区：描述你想构建的东西，选择一个模式，剩下的交给你的 agent。</em></p>\n<h2 id=\"what-is-open-design\">什么是 Open Design？</h2>\n<p>Open Design 是一个开源、本地优先的设计平台——一个 agent 原生的 Claude Design 替代方案。所谓“AI 紫色糊状物”问题（每个生成的 UI 看起来都一样）正是这类工具想要解决的，而 Open Design 的答案是<strong>运行在你已经在用的编码 agent 之上</strong>，而不是自带一个模型。它会检测你机器上的 Claude Code、Codex、Cursor、Gemini、OpenCode 等，并以此作为引擎。用 Sasha 的话说：它之所以在第一周就收获数万个 GitHub star，是因为它免费、开源，且不被绑定在某一家服务商上。</p>\n<ul>\n<li><strong>开源，Apache-2.0</strong>——可克隆、可阅读、可自托管。</li>\n<li><strong>本地运行</strong>——你的项目就是你自己机器上的文件夹。</li>\n<li><strong>任意 agent、任意模型</strong>——包括通过任意兼容 OpenAI 的服务商使用你自己的 API key。</li>\n<li>内置<strong>丰富的设计技能与设计系统库</strong>。</li>\n<li><strong>不止原型</strong>——还有幻灯片、图片，甚至视频。</li>\n</ul>\n<h2 id=\"step-1--install-and-configure\">第 1 步——安装并配置</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>打开它打印出的本地 URL（端口是动态的——不要写死）。想要零配置？从 <a href=\"https://open-design.ai/download\">open-design.ai/download</a> 获取<strong>桌面应用</strong>。首次启动时，设置页会检测你机器上的 agent CLI——Sasha 用的是 Codex——并允许你设置默认模型、添加媒体服务商（MiniMax、OpenAI GPT Image 等）、连接数据源、切换语言并挑选主题。</p>\n<h2 id=\"step-2--use-any-model-via-an-openai-compatible-provider\">第 2 步——通过兼容 OpenAI 的服务商使用任意模型</h2>\n<p>这是 Sasha 评测中最有价值的一点。除了被检测到的 CLI，Open Design 还允许你<strong>为任意兼容 OpenAI 的 API 自带 key</strong>——这意味着你可以经由 OpenRouter 这样的聚合器路由，使用几乎任意模型，往往还更便宜：</p>\n<ol>\n<li>在你的服务商处创建一个 API key 并复制它。</li>\n<li>在 Open Design 设置中，选择 <strong>OpenAI</strong> 服务商类型（OpenRouter 及类似聚合器都使用 OpenAI API）。</li>\n<li>粘贴 key，关键是要<strong>修改 base URL</strong> 为你服务商的端点（例如 OpenRouter 的 base URL），然后选择你想要的模型。</li>\n<li>保存——现在生成就会经由该服务商路由。</li>\n</ol>\n<p>Sasha 踩到的一个坑：模型选择是<strong>全局</strong>切换的，而非按项目，所以如果切换后媒体生成出问题，那是因为图片服务商跟着模型一起被切换了。请显式设置你的媒体服务商 key。</p>\n<h2 id=\"step-3--build-a-prototype-rough-edges-and-all\">第 3 步——构建一个原型（连粗糙之处一并呈现）</h2>\n<p>创建一个项目，写下你的需求简介，选择<strong>高保真</strong>，然后发送。Open Design 会先运行一个<strong>探索表单</strong>——它会根据你的提示调整问题（目标平台、面向谁、调性、动画、约束），接着是<strong>视觉方向选择器</strong>（字体 + 配色），然后开始构建。输出是一个实时、可交互的原型，自带控件——Sasha 生成的应用让你可以直接在页面上切换动画、更换强调色。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/generated-prototype.webp\" alt=\"在 Open Design 中生成的一个真实原型。\">\n<em>在预览中渲染的一个真实生成原型——一个暗色、富电影感的代理公司落地页。</em></p>\n<p>Sasha 在镜头前展示的诚实告诫（以及应对方法）：</p>\n<ul>\n<li><strong>它可能默认选错技能。</strong>如果你想要一个移动应用，它却开始构建一个“checkpoint/blog”，就明确告诉它：“使用 mobile-app / front-end 技能。”在生成前先设定好技能。</li>\n<li><strong>Inspect 需要 <code>data-oid</code> 标签。</strong>画布上的 Inspect 工具需要产物被打上标签；如果它说无法选中元素，就让 agent “用 data-oid 标签重新构建原型”，然后重新加载。</li>\n<li><strong>它还年轻，且发布很快。</strong>预期会偶有故障（编辑后导航消失等）——这个项目几乎每天更新，所以要勤拉取。</li>\n</ul>\n<h2 id=\"step-4--the-on-canvas-tools-the-real-draw\">第 4 步——画布上的工具（真正的看点）</h2>\n<p>一旦打好标签，编辑循环就是它的亮点。<strong>Inspect</strong> 让你悬停在任意元素上，直接调整颜色、尺寸和样式。<strong>Edit</strong> 让你就地改写文字（改一个词无需往返聊天）。<strong>Comment/picker</strong> 让你选定一块区域、绘制并向 agent 发送一条说明（“把这个菜单做成带进度条的滚动轮播”）。这是一个快速、可视化的反馈循环，用终端里的纯 agent 很难复现。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/plugins-hub.webp\" alt=\"Open Design 插件中心。\">\n<em>插件中心：浏览注册表、导入插件，并为你的团队做好准备。</em></p>\n<p>完成后，<strong>Share</strong> 可导出为 PDF、PPTX、独立 HTML 或 markdown——或一键部署到 Vercel。Sasha 的诚实结论：对于演示文稿和引流页，它已经是一个方便的迷你构建器；对于复杂的应用/网站原型，则要做真正的迭代。考虑到它才发布一周且持续更新，根基已经很扎实。</p>\n<h2 id=\"tips\">小贴士</h2>\n<ul>\n<li><strong>接入 OpenRouter（或任意兼容 OpenAI 的服务商）</strong>以使用更便宜或不同的模型——记得修改 base URL。</li>\n<li>在生成前<strong>显式设定技能</strong>，以免它默认选错模板。</li>\n<li>如果 Inspect 选不中元素，就<strong>要求打上 <code>data-oid</code> 标签</strong>，然后重新加载。</li>\n<li><strong>多依赖 Inspect/Edit/Comment</strong> 做快速可视化微调，而不是在聊天里重新提示。</li>\n<li><strong>勤拉取</strong>——这个项目几乎每天都在发布修复。</li>\n</ul>\n<h2 id=\"faq\">常见问题</h2>\n<p><strong>我能用 Claude 以外的模型，并且花更少的钱吗？</strong>\n可以。把 Open Design 指向任意被检测到的 CLI，或为任意兼容 OpenAI 的服务商（例如 OpenRouter）自带 key——设置好 key 和 base URL 即可——这就打开了几乎任意模型的大门。</p>\n<p><strong>Inspect/edit 选不中元素——为什么？</strong>\n产物需要 <code>data-oid</code> 标签。让 agent 带着这些标签重新构建原型，然后重新加载预览。</p>\n<p><strong>它能用于生产环境吗？</strong>\n它还处于早期、迭代很快。对于幻灯片和引流页它已经很棒；对于复杂应用，请把输出当作一份你需要打磨的扎实初稿。</p>\n<p><strong>它免费吗？</strong>\n该应用在 Apache-2.0 下开源，本地运行免费。你只需为所连接的那家 agent 和服务商的模型与媒体用量付费。</p>\n<hr>\n<p><em>这份文字指南基于 Sasha（ИИШНЫЙ）的实操评测。观看上方完整视频，并<a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">订阅 ИИШНЫЙ</a> 以获取更多诚实、未剪辑的 AI 工具测评。</em></p>",
  },
  "ja": {
    title: "Open Design — 正直なファーストインプレッション（バグ、回避策、任意モデルのセットアップ）",
    summary: "Open Design の包み隠さないファーストインプレッション——インストール、任意の agent の設定、実際のプロトタイプをライブで構築（粗削りな部分も含めて）、キャンバス上の編集/検査/コメントツールの利用、そして OpenRouter のような OpenAI 互換プロバイダーを通じて任意のモデルを安価に接続する方法。Sasha（ИИШНЫЙ）の実機レビューに基づく。",
    bodyHtml: "<p>本ガイドは Open Design に対するあえて率直なファーストインプレッションです。きちんと動く部分も、ぶつかるであろう粗削りな部分も、編集で隠さずそのまま見せています。さらに、OpenAI 互換プロバイダーを通じて<em>あらゆる</em>モデルを低コストで接続するという、本当に役立つテクニックも紹介します。内容は <strong>Sasha（ИИШНЫЙ）</strong>が<a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">ウォークスルー</a>で記録した実践レビューに基づき、本記事向けに再構成し、最新リリースに合わせて更新しています。実際の操作は上の動画でご覧いただくか、続けて記事版をお読みください。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/workspace-home.webp\" alt=\"Open Design のワークスペース——作りたいものを記述してモードを選ぶ。\">\n<em>Open Design のワークスペース：作りたいものを記述し、モードを選べば、あとは agent がやってくれる。</em></p>\n<h2 id=\"what-is-open-design\">Open Design とは？</h2>\n<p>Open Design は、オープンソースかつローカルファーストのデザインプラットフォーム——Claude Design に対する agent ネイティブな代替です。「AI の紫色のスロップ」問題（生成される UI がどれも同じに見える）こそ、この種のツールが解こうとしているもので、Open Design の答えは独自のモデルを出荷するのではなく、<strong>あなたがすでに使っているコーディング agent の上で動く</strong>ことです。マシン上の Claude Code、Codex、Cursor、Gemini、OpenCode などを検出し、それをエンジンとして使います。Sasha の見立てでは：無料・オープンで、特定のプロバイダーに縛られないからこそ、最初の一週間で数万の GitHub スターを集めたのです。</p>\n<ul>\n<li><strong>オープンソース、Apache-2.0</strong>——クローンして、読んで、セルフホストできる。</li>\n<li><strong>ローカルで動く</strong>——プロジェクトは自分のマシン上のフォルダー。</li>\n<li><strong>任意の agent、任意のモデル</strong>——任意の OpenAI 互換プロバイダー経由で自分の API key を使うことも含む。</li>\n<li><strong>充実したデザインスキルとデザインシステムのライブラリ</strong>を内蔵。</li>\n<li><strong>プロトタイプにとどまらない</strong>——スライドデッキ、画像、さらには動画まで。</li>\n</ul>\n<h2 id=\"step-1--install-and-configure\">ステップ 1 — インストールと設定</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>表示されたローカル URL を開きます（ポートは動的です——ハードコードしないこと）。セットアップ不要が良いですか？<a href=\"https://open-design.ai/download\">open-design.ai/download</a> から<strong>デスクトップアプリ</strong>を入手しましょう。初回起動時、設定ページがマシン上の agent CLI を検出し——Sasha は Codex を使用——デフォルトモデルの設定、メディアプロバイダー（MiniMax、OpenAI GPT Image など）の追加、データソースの接続、言語の切り替え、テーマの選択ができます。</p>\n<h2 id=\"step-2--use-any-model-via-an-openai-compatible-provider\">ステップ 2 — OpenAI 互換プロバイダー経由で任意のモデルを使う</h2>\n<p>これが Sasha のレビューで最も役立つ要点です。検出された CLI のほかに、Open Design では<strong>任意の OpenAI 互換 API に自分の key を持ち込める</strong>——つまり OpenRouter のようなアグリゲーター経由でルーティングし、ほぼ任意のモデルを、しばしばより安価に使えるということです：</p>\n<ol>\n<li>プロバイダーで API key を作成してコピーします。</li>\n<li>Open Design の設定で、<strong>OpenAI</strong> プロバイダータイプを選びます（OpenRouter などのアグリゲーターは OpenAI API を話します）。</li>\n<li>key を貼り付け、肝心なのは <strong>base URL を変更</strong>してプロバイダーのエンドポイント（例：OpenRouter の base URL）にし、使いたいモデルを選ぶことです。</li>\n<li>保存——これで生成はそのプロバイダー経由でルーティングされます。</li>\n</ol>\n<p>Sasha がぶつかった落とし穴：モデル選択はプロジェクトごとではなく<strong>グローバル</strong>に切り替わります。なので切り替え後にメディア生成が壊れたら、それは画像プロバイダーがモデルの切り替えに追従したからです。メディアプロバイダーの key は明示的に設定してください。</p>\n<h2 id=\"step-3--build-a-prototype-rough-edges-and-all\">ステップ 3 — プロトタイプを構築する（粗削りな部分も含めて）</h2>\n<p>プロジェクトを作成し、ブリーフを書き、<strong>ハイフィデリティ</strong>を選んで送信します。Open Design はまず<strong>ディスカバリーフォーム</strong>を実行します——プロンプトに合わせて質問を調整し（対象プラットフォーム、誰向けか、トーン、アニメーション、制約）、続いて<strong>ビジュアル方向のピッカー</strong>（タイポグラフィ＋パレット）、それから構築します。出力は、組み込みコントロール付きのライブでインタラクティブなプロトタイプです——Sasha が生成したアプリでは、ページ上で直接アニメーションを切り替えたり、アクセントカラーを差し替えたりできます。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/generated-prototype.webp\" alt=\"Open Design で生成された実際のプロトタイプ。\">\n<em>プレビューでレンダリングされた実際の生成プロトタイプ——ダークで映画的なエージェンシーのランディングページ。</em></p>\n<p>Sasha がカメラの前で見せた正直な注意点（とその対処法）：</p>\n<ul>\n<li><strong>間違ったスキルがデフォルトで選ばれることがある。</strong>モバイルアプリが欲しいのに「checkpoint/blog」を作り始めたら、明示的に伝えましょう：「mobile-app / front-end スキルを使って」。生成前にスキルを設定しておくこと。</li>\n<li><strong>Inspect には <code>data-oid</code> タグが必要。</strong>キャンバス上の Inspect ツールは成果物にタグが付いている必要があります。要素を選べないと言われたら、agent に「data-oid タグ付きでプロトタイプを作り直して」と頼み、リロードします。</li>\n<li><strong>まだ若く、リリースが速い。</strong>時折の不具合（編集後にナビゲーションが消えるなど）は想定しておきましょう——プロジェクトはほぼ毎日更新されるので、こまめに再プルしてください。</li>\n</ul>\n<h2 id=\"step-4--the-on-canvas-tools-the-real-draw\">ステップ 4 — キャンバス上のツール（本当の見どころ）</h2>\n<p>タグ付けされれば、編集ループこそが目玉です。<strong>Inspect</strong> では任意の要素にホバーして、色・サイズ・スタイルを直接調整できます。<strong>Edit</strong> ではテキストをインラインで書き換えられます（一語の変更のためにチャットを往復しなくて済む）。<strong>Comment/picker</strong> では領域を選択し、描き込んで、agent にメモを送れます（「このメニューをプログレスバー付きのスクロールするカルーセルにして」）。これは、ターミナル内の素の agent では再現しづらい、速くてビジュアルなフィードバックループです。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/plugins-hub.webp\" alt=\"Open Design のプラグインハブ。\">\n<em>プラグインハブ：レジストリを閲覧し、プラグインをインポートし、チーム向けに準備する。</em></p>\n<p>完了したら、<strong>Share</strong> で PDF、PPTX、スタンドアロン HTML、または markdown にエクスポート——あるいはワンクリックで Vercel にデプロイできます。Sasha の正直な評価：プレゼンテーションやリードマグネットのページには、すでに便利なミニビルダーです。複雑なアプリ/サイトのプロトタイピングには、相応の反復が必要だと思っておきましょう。まだ一週間しか経っておらず絶えず更新されていることを踏まえれば、土台はしっかりしています。</p>\n<h2 id=\"tips\">ヒント</h2>\n<ul>\n<li>より安価な、あるいは別のモデルを使うために <strong>OpenRouter（または任意の OpenAI 互換プロバイダー）を接続</strong>——base URL の変更を忘れずに。</li>\n<li>間違ったテンプレートがデフォルトにならないよう、生成前に<strong>スキルを明示的に設定</strong>する。</li>\n<li>Inspect が要素を選べない場合は <strong><code>data-oid</code> タグを要求</strong>し、リロードする。</li>\n<li>チャットで再プロンプトする代わりに、素早いビジュアル調整には <strong>Inspect/Edit/Comment を活用</strong>する。</li>\n<li><strong>こまめに再プル</strong>——プロジェクトはほぼ毎日修正を出している。</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Claude 以外のモデルを使って、しかも安く済ませられますか？</strong>\nはい。Open Design を任意の検出済み CLI に向けるか、任意の OpenAI 互換プロバイダー（例：OpenRouter）に key と base URL を設定して自分の key を持ち込めば——ほぼ任意のモデルが開けます。</p>\n<p><strong>Inspect/edit が要素を選べません——なぜ？</strong>\n成果物に <code>data-oid</code> タグが必要です。agent にそれを付けてプロトタイプを作り直してもらい、プレビューをリロードしてください。</p>\n<p><strong>本番運用に耐えますか？</strong>\nまだ初期段階で、速く反復しています。デッキやリードマグネットのページにはすでに最適です。複雑なアプリでは、出力を磨き上げる前の出来の良い下書きとして扱いましょう。</p>\n<p><strong>無料ですか？</strong>\nアプリは Apache-2.0 のもとでオープンソースで、ローカル実行は無料です。支払うのは、接続した agent とプロバイダーのモデルおよびメディア利用分だけです。</p>\n<hr>\n<p><em>この文章ガイドは Sasha（ИИШНЫЙ）の実機レビューに基づいています。上の完全な動画をご覧いただき、より正直で未編集な AI ツールテストについては <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">ИИШНЫЙ を購読</a>してください。</em></p>",
  },
  "ko": {
    title: "Open Design — 솔직한 첫인상 (버그, 해결책, 그리고 임의 모델 설정)",
    summary: "Open Design에 대한 가감 없는 첫인상 — 설치하고, 임의의 agent를 설정하고, 실제 프로토타입을 라이브로 만들어 보고(거친 부분까지 그대로), 캔버스 위의 편집/검사/코멘트 도구를 사용하며, OpenRouter 같은 OpenAI 호환 제공자를 통해 임의의 모델을 저렴하게 연결합니다. Sasha(ИИШНЫЙ)의 실사용 리뷰를 바탕으로 합니다.",
    bodyHtml: "<p>이 가이드는 Open Design에 대한 일부러 솔직하게 담은 첫인상입니다. 잘 작동하는 부분과 마주치게 될 거친 부분을 편집으로 가리지 않고 그대로 실시간으로 보여 줍니다. 또한 OpenAI 호환 제공업체를 통해 <em>어떤</em> 모델이든 저렴하게 연결하는 정말 유용한 요령도 다룹니다. <strong>Sasha(ИИШНЫЙ)</strong>가 <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">워크스루</a>에서 기록한 실습 리뷰를 바탕으로, 이 글에 맞게 재구성하고 최신 릴리스에 맞춰 업데이트했습니다. 실제 실행은 위 영상으로 보시거나, 계속해서 글 버전을 읽어 보세요.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/workspace-home.webp\" alt=\"Open Design 워크스페이스 — 원하는 것을 설명하고 모드를 선택하세요.\">\n<em>Open Design 워크스페이스: 만들고 싶은 것을 설명하고, 모드를 고르면, 나머지는 agent가 합니다.</em></p>\n<h2 id=\"what-is-open-design\">Open Design이란?</h2>\n<p>Open Design은 오픈소스이자 로컬 우선 디자인 플랫폼 — Claude Design에 대한 agent 네이티브 대안입니다. \"AI 보라색 슬롭\" 문제(생성된 모든 UI가 똑같아 보이는 것)야말로 이런 도구들이 풀려는 것이며, Open Design의 답은 자체 모델을 출시하기보다 <strong>당신이 이미 쓰고 있는 코딩 agent 위에서 동작</strong>하는 것입니다. 당신의 머신에서 Claude Code, Codex, Cursor, Gemini, OpenCode 등을 감지해 이를 엔진으로 사용합니다. Sasha의 표현: 무료이고 오픈되어 있으며 특정 제공자에 묶이지 않았기에, 첫 주에 수만 개의 GitHub 스타를 모았습니다.</p>\n<ul>\n<li><strong>오픈소스, Apache-2.0</strong> — 클론하고, 읽고, 자체 호스팅할 수 있습니다.</li>\n<li><strong>로컬에서 실행</strong> — 당신의 프로젝트는 당신 머신 위의 폴더입니다.</li>\n<li><strong>임의의 agent, 임의의 모델</strong> — 임의의 OpenAI 호환 제공자를 통해 당신의 API key를 쓰는 것까지 포함합니다.</li>\n<li><strong>풍부한 디자인 스킬과 디자인 시스템 라이브러리</strong>를 내장.</li>\n<li><strong>프로토타입 이상</strong> — 슬라이드 덱, 이미지, 심지어 영상까지.</li>\n</ul>\n<h2 id=\"step-1--install-and-configure\">1단계 — 설치 및 설정</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>출력되는 로컬 URL을 엽니다(포트는 동적입니다 — 하드코딩하지 마세요). 설정 없이 바로 쓰고 싶나요? <a href=\"https://open-design.ai/download\">open-design.ai/download</a>에서 <strong>데스크톱 앱</strong>을 받으세요. 첫 실행 시 설정 페이지가 머신의 agent CLI를 감지하고 — Sasha는 Codex를 사용 — 기본 모델 설정, 미디어 제공자(MiniMax, OpenAI GPT Image 등) 추가, 데이터 소스 연결, 언어 전환, 테마 선택을 할 수 있게 해 줍니다.</p>\n<h2 id=\"step-2--use-any-model-via-an-openai-compatible-provider\">2단계 — OpenAI 호환 제공자를 통해 임의의 모델 사용하기</h2>\n<p>이것이 Sasha 리뷰에서 가장 유용한 핵심입니다. 감지된 CLI 외에도 Open Design은 <strong>임의의 OpenAI 호환 API에 당신의 key를 가져와 쓸 수 있게</strong> 합니다 — 즉 OpenRouter 같은 애그리게이터를 통해 라우팅해서 거의 모든 모델을, 흔히 더 저렴하게 쓸 수 있다는 뜻입니다:</p>\n<ol>\n<li>제공자에서 API key를 생성하고 복사합니다.</li>\n<li>Open Design 설정에서 <strong>OpenAI</strong> 제공자 유형을 선택합니다(OpenRouter 및 유사 애그리게이터는 OpenAI API를 사용합니다).</li>\n<li>key를 붙여넣고, 무엇보다 <strong>base URL을 변경</strong>해 제공자의 엔드포인트(예: OpenRouter base URL)로 바꾼 뒤, 원하는 모델을 선택합니다.</li>\n<li>저장 — 이제 생성이 그 제공자를 통해 라우팅됩니다.</li>\n</ol>\n<p>Sasha가 부딪힌 함정 하나: 모델 선택은 프로젝트별이 아니라 <strong>전역으로</strong> 전환됩니다. 따라서 전환 후 미디어 생성이 깨진다면, 그것은 이미지 제공자가 모델 전환을 따라갔기 때문입니다. 미디어 제공자 key는 명시적으로 설정하세요.</p>\n<h2 id=\"step-3--build-a-prototype-rough-edges-and-all\">3단계 — 프로토타입 만들기(거친 부분까지 그대로)</h2>\n<p>프로젝트를 만들고, 브리프를 작성하고, <strong>하이 피델리티</strong>를 선택한 뒤 보냅니다. Open Design은 먼저 <strong>디스커버리 폼</strong>을 실행합니다 — 프롬프트에 맞춰 질문을 조정하고(대상 플랫폼, 누구를 위한 것인지, 톤, 애니메이션, 제약), 이어 <strong>비주얼 방향 선택기</strong>(타이포그래피 + 팔레트), 그다음 빌드합니다. 결과물은 내장 컨트롤이 있는 라이브 인터랙티브 프로토타입입니다 — Sasha가 생성한 앱은 페이지에서 바로 애니메이션을 토글하고 강조색을 바꿀 수 있습니다.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/generated-prototype.webp\" alt=\"Open Design에서 생성된 실제 프로토타입.\">\n<em>프리뷰에서 렌더링된 실제 생성 프로토타입 — 어둡고 영화적인 에이전시 랜딩 페이지.</em></p>\n<p>Sasha가 카메라 앞에서 보여준 솔직한 주의점(과 대처법):</p>\n<ul>\n<li><strong>잘못된 스킬이 기본 선택될 수 있습니다.</strong> 모바일 앱을 원했는데 \"checkpoint/blog\"를 만들기 시작하면, 명시적으로 말하세요: \"mobile-app / front-end 스킬을 사용해.\" 생성 전에 스킬을 설정하세요.</li>\n<li><strong>Inspect에는 <code>data-oid</code> 태그가 필요합니다.</strong> 캔버스의 Inspect 도구는 아티팩트에 태그가 붙어 있어야 합니다. 요소를 선택할 수 없다고 하면 agent에게 \"data-oid 태그를 붙여 프로토타입을 다시 만들어\"라고 요청한 뒤 새로고침하세요.</li>\n<li><strong>아직 초기이고 빠르게 배포됩니다.</strong> 가끔의 결함(편집 후 내비게이션이 사라지는 등)을 예상하세요 — 프로젝트는 거의 매일 업데이트되므로 자주 다시 풀하세요.</li>\n</ul>\n<h2 id=\"step-4--the-on-canvas-tools-the-real-draw\">4단계 — 캔버스 위의 도구들(진짜 매력)</h2>\n<p>태그가 붙으면, 편집 루프가 백미입니다. <strong>Inspect</strong>는 임의의 요소에 호버해 색상, 크기, 스타일을 직접 조정하게 해 줍니다. <strong>Edit</strong>는 텍스트를 인라인으로 다시 쓰게 해 줍니다(단어 하나 바꾸려고 채팅을 오갈 필요가 없습니다). <strong>Comment/picker</strong>는 영역을 선택하고, 그려서, agent에게 메모를 보낼 수 있게 해 줍니다(\"이 메뉴를 진행 표시줄이 있는 스크롤 캐러셀로 만들어\"). 터미널의 순수 agent로는 재현하기 어색한, 빠르고 시각적인 피드백 루프입니다.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/plugins-hub.webp\" alt=\"Open Design 플러그인 허브.\">\n<em>플러그인 허브: 레지스트리를 둘러보고, 플러그인을 가져오고, 팀을 위해 준비합니다.</em></p>\n<p>끝나면 <strong>Share</strong>로 PDF, PPTX, 독립 실행형 HTML 또는 markdown으로 내보내거나 — 한 번의 클릭으로 Vercel에 배포할 수 있습니다. Sasha의 솔직한 평가: 프레젠테이션과 리드 마그넷 페이지에는 이미 편리한 미니 빌더입니다. 복잡한 앱/사이트 프로토타이핑에는 실질적인 반복 작업이 필요할 거라고 보세요. 나온 지 일주일밖에 안 됐고 끊임없이 업데이트되는 점을 감안하면, 기반은 탄탄합니다.</p>\n<h2 id=\"tips\">팁</h2>\n<ul>\n<li>더 저렴하거나 다른 모델을 쓰려면 <strong>OpenRouter(또는 임의의 OpenAI 호환 제공자)를 연결</strong>하세요 — base URL 변경을 잊지 마세요.</li>\n<li>잘못된 템플릿이 기본으로 선택되지 않도록 생성 전에 <strong>스킬을 명시적으로 설정</strong>하세요.</li>\n<li>Inspect가 요소를 선택하지 못하면 <strong><code>data-oid</code> 태그를 요청</strong>한 뒤 새로고침하세요.</li>\n<li>채팅에서 다시 프롬프트하는 대신, 빠른 시각적 조정에는 <strong>Inspect/Edit/Comment에 의존</strong>하세요.</li>\n<li><strong>자주 다시 풀하세요</strong> — 프로젝트는 거의 매일 수정 사항을 배포합니다.</li>\n</ul>\n<h2 id=\"faq\">자주 묻는 질문</h2>\n<p><strong>Claude 외의 모델을 쓰면서 — 더 적게 낼 수 있나요?</strong>\n네. Open Design을 임의의 감지된 CLI에 연결하거나, 임의의 OpenAI 호환 제공자(예: OpenRouter)에 key와 base URL을 설정해 당신의 key를 가져오면 — 거의 모든 모델이 열립니다.</p>\n<p><strong>Inspect/edit가 요소를 선택하지 못해요 — 왜죠?</strong>\n아티팩트에 <code>data-oid</code> 태그가 필요합니다. agent에게 그 태그를 붙여 프로토타입을 다시 만들어 달라고 한 뒤, 프리뷰를 새로고침하세요.</p>\n<p><strong>프로덕션에 바로 쓸 수 있나요?</strong>\n초기 단계이고 빠르게 반복 중입니다. 덱과 리드 마그넷 페이지에는 이미 훌륭합니다. 복잡한 앱에는 출력물을 다듬어야 할 탄탄한 초안으로 다루세요.</p>\n<p><strong>무료인가요?</strong>\n앱은 Apache-2.0 하에 오픈소스이며 로컬 실행은 무료입니다. 연결한 agent와 제공자의 모델 및 미디어 사용분에 대해서만 비용을 냅니다.</p>\n<hr>\n<p><em>이 텍스트 가이드는 Sasha(ИИШНЫЙ)의 실사용 리뷰를 바탕으로 합니다. 위의 전체 영상을 보시고, 더 솔직하고 편집되지 않은 AI 도구 테스트를 보려면 <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">ИИШНЫЙ를 구독</a>하세요.</em></p>",
  },
  "de": {
    title: "Open Design — ein ehrlicher erster Eindruck (Bugs, Workarounds und Einrichtung mit beliebigem Modell)",
    summary: "Ein ungeschönter erster Eindruck von Open Design — installieren, einen beliebigen Agent konfigurieren, live einen echten Prototyp bauen (raue Kanten inklusive), die Edit-/Inspect-/Comment-Werkzeuge direkt auf der Leinwand nutzen und über einen OpenAI-kompatiblen Anbieter wie OpenRouter günstig ein beliebiges Modell anbinden. Basierend auf dem praxisnahen Test von Sasha (ИИШНЫЙ).",
    bodyHtml: "<p>Dieser Leitfaden ist ein bewusst ehrlicher erster Blick auf Open Design – die Dinge, die einfach funktionieren, und die rauen Kanten, auf die du stoßen wirst, live gezeigt statt herausgeschnitten. Außerdem geht es um einen wirklich nützlichen Kniff: <em>jedes</em> Modell günstig über einen OpenAI-kompatiblen Anbieter einzubinden. Er folgt dem praktischen Test, den <strong>Sasha (ИИШНЫЙ)</strong> in <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">seinem Walkthrough</a> aufzeichnet, für diesen Textbeitrag aufbereitet und auf den aktuellen Release gebracht. Sieh dir das Video oben für den Live-Durchlauf an oder lies weiter für die Textversion.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/workspace-home.webp\" alt=\"Der Open-Design-Arbeitsbereich — beschreibe, was du willst, und wähle einen Modus.\">\n<em>Der Open-Design-Arbeitsbereich: beschreibe, was du bauen möchtest, wähle einen Modus, und dein Agent erledigt den Rest.</em></p>\n<h2 id=\"what-is-open-design\">Was ist Open Design?</h2>\n<p>Open Design ist eine quelloffene, local-first Designplattform — eine agent-native Alternative zu Claude Design. Das Problem des „lila KI-Einheitsbreis\" (jede generierte UI sieht gleich aus) ist genau das, was Werkzeuge wie dieses zu lösen versuchen, und Open Designs Antwort ist, <strong>auf dem Coding-Agent zu laufen, den du ohnehin schon nutzt</strong>, statt ein eigenes Modell auszuliefern. Es erkennt Claude Code, Codex, Cursor, Gemini, OpenCode und mehr auf deinem Rechner und nutzt das als Engine. Sashas Einordnung: Es sammelte in der ersten Woche Zehntausende GitHub-Sterne, weil es kostenlos, offen und an keinen einzelnen Anbieter gebunden ist.</p>\n<ul>\n<li><strong>Quelloffen, Apache-2.0</strong> — klone es, lies es, hoste es selbst.</li>\n<li><strong>Läuft lokal</strong> — deine Projekte sind Ordner auf deinem eigenen Rechner.</li>\n<li><strong>Beliebiger Agent, beliebiges Modell</strong> — einschließlich deines eigenen API-Schlüssels über einen beliebigen OpenAI-kompatiblen Anbieter.</li>\n<li>Eine <strong>umfangreiche Bibliothek an Design-Skills und Designsystemen</strong> ist eingebaut.</li>\n<li><strong>Mehr als nur Prototypen</strong> — Foliensätze, Bilder, sogar Video.</li>\n</ul>\n<h2 id=\"step-1--install-and-configure\">Schritt 1 — Installieren und konfigurieren</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Öffne die lokale URL, die es ausgibt (ein dynamischer Port — schreibe ihn nicht fest). Du bevorzugst null Einrichtung? Hol dir die <strong>Desktop-App</strong> von <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. Beim ersten Start erkennt die Einstellungsseite die Agent-CLIs auf deinem Rechner — Sasha nutzt Codex — und lässt dich ein Standardmodell festlegen, Medienanbieter hinzufügen (MiniMax, OpenAI GPT Image und mehr), Datenquellen verbinden, die Sprache wechseln und ein Theme wählen.</p>\n<h2 id=\"step-2--use-any-model-via-an-openai-compatible-provider\">Schritt 2 — Ein beliebiges Modell über einen OpenAI-kompatiblen Anbieter nutzen</h2>\n<p>Das ist die nützlichste Erkenntnis in Sashas Test. Über die erkannten CLIs hinaus lässt dich Open Design <strong>deinen eigenen Schlüssel für jede OpenAI-kompatible API mitbringen</strong> — das heißt, du kannst über einen Aggregator wie OpenRouter routen und nahezu jedes Modell nutzen, oft günstiger:</p>\n<ol>\n<li>Erstelle bei deinem Anbieter einen API-Schlüssel und kopiere ihn.</li>\n<li>Wähle in den Open-Design-Einstellungen den Anbietertyp <strong>OpenAI</strong> (OpenRouter und ähnliche Aggregatoren sprechen die OpenAI API).</li>\n<li>Füge den Schlüssel ein und — entscheidend — <strong>ändere die base URL</strong> auf den Endpunkt deines Anbieters (z. B. die OpenRouter base URL), und wähle dann das gewünschte Modell.</li>\n<li>Speichern — die Generierung läuft nun über diesen Anbieter.</li>\n</ol>\n<p>Ein Stolperstein, auf den Sasha trifft: Die Modellauswahl schaltet <strong>global</strong> um, nicht pro Projekt; wenn die Mediengenerierung nach dem Wechsel kaputtgeht, liegt das also daran, dass der Bildanbieter dem Modellwechsel gefolgt ist. Lege die Schlüssel deiner Medienanbieter ausdrücklich fest.</p>\n<h2 id=\"step-3--build-a-prototype-rough-edges-and-all\">Schritt 3 — Einen Prototyp bauen (raue Kanten und alles)</h2>\n<p>Lege ein Projekt an, schreibe dein Briefing, wähle <strong>High Fidelity</strong> und sende ab. Open Design führt zuerst ein <strong>Discovery-Formular</strong> aus — es passt die Fragen an deinen Prompt an (Zielplattform, für wen, Tonalität, Animation, Einschränkungen), dann einen <strong>Auswahldialog für die visuelle Richtung</strong> (Typografie + Palette) und baut anschließend. Das Ergebnis ist ein lebendiger, interaktiver Prototyp mit eingebauten Steuerelementen — Sashas generierte App lässt dich Animationen umschalten und die Akzentfarbe direkt auf der Seite austauschen.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/generated-prototype.webp\" alt=\"Ein echter, in Open Design generierter Prototyp.\">\n<em>Ein echter generierter Prototyp, in der Vorschau gerendert — eine dunkle, cineastische Agentur-Landingpage.</em></p>\n<p>Ehrliche Vorbehalte, die Sasha vor der Kamera zeigt (und wie man damit umgeht):</p>\n<ul>\n<li><strong>Es wählt vielleicht standardmäßig den falschen Skill.</strong> Wenn es einen „checkpoint/blog\" zu bauen beginnt, während du eine Mobile-App wolltest, sag es ihm ausdrücklich: „nutze den mobile-app / front-end Skill.\" Lege den Skill fest, bevor du generierst.</li>\n<li><strong>Inspect benötigt <code>data-oid</code>-Tags.</strong> Das Inspect-Werkzeug auf der Leinwand braucht ein getaggtes Artefakt; wenn es meldet, dass es keine Elemente auswählen kann, bitte den Agent, „den Prototyp mit data-oid-Tags neu zu bauen\", und lade dann neu.</li>\n<li><strong>Es ist jung und liefert schnell aus.</strong> Rechne mit gelegentlichen Aussetzern (Navigation verschwindet nach einer Bearbeitung usw.) — das Projekt aktualisiert sich fast täglich, also zieh oft erneut.</li>\n</ul>\n<h2 id=\"step-4--the-on-canvas-tools-the-real-draw\">Schritt 4 — Die Werkzeuge auf der Leinwand (das eigentliche Highlight)</h2>\n<p>Sobald getaggt, ist die Bearbeitungsschleife das Herausragende. Mit <strong>Inspect</strong> kannst du über jedes Element fahren und Farbe, Größe und Stil direkt anpassen. Mit <strong>Edit</strong> kannst du Text inline umschreiben (kein Hin und Her zum Chat für eine Änderung an einem Wort). Mit <strong>Comment/picker</strong> kannst du einen Bereich auswählen, zeichnen und dem Agent eine Notiz schicken („mach aus diesem Menü ein scrollendes Karussell mit Fortschrittsbalken\"). Es ist die schnelle, visuelle Feedbackschleife, die sich mit einem schlichten Agent im Terminal nur umständlich nachbilden lässt.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/plugins-hub.webp\" alt=\"Der Open-Design-Plugin-Hub.\">\n<em>Der Plugin-Hub: durchstöbere die Registry, importiere Plugins und mache sie für dein Team bereit.</em></p>\n<p>Wenn du fertig bist, exportiert <strong>Share</strong> nach PDF, PPTX, eigenständigem HTML oder markdown — oder deployt mit einem Klick auf Vercel. Sashas ehrliches Fazit: Für Präsentationen und Lead-Magnet-Seiten ist es bereits ein praktischer Mini-Builder; für komplexes App-/Site-Prototyping rechne mit echter Iteration. Da es erst eine Woche alt ist und ständig aktualisiert wird, ist das Fundament stark.</p>\n<h2 id=\"tips\">Tipps</h2>\n<ul>\n<li><strong>Binde OpenRouter (oder einen beliebigen OpenAI-kompatiblen Anbieter) an</strong>, um günstigere oder andere Modelle zu nutzen — denk daran, die base URL zu ändern.</li>\n<li><strong>Lege den Skill ausdrücklich fest</strong>, bevor du generierst, damit es nicht standardmäßig die falsche Vorlage wählt.</li>\n<li><strong>Fordere <code>data-oid</code>-Tags an</strong>, wenn Inspect keine Elemente auswählen kann, und lade dann neu.</li>\n<li><strong>Setze auf Inspect/Edit/Comment</strong> für schnelle visuelle Anpassungen, statt im Chat neu zu prompten.</li>\n<li><strong>Zieh oft erneut</strong> — das Projekt liefert fast täglich Fehlerbehebungen aus.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Kann ich ein anderes Modell als Claude nutzen — und weniger zahlen?</strong>\nJa. Richte Open Design auf eine beliebige erkannte CLI aus oder bring deinen eigenen Schlüssel für einen beliebigen OpenAI-kompatiblen Anbieter (z. B. OpenRouter) mit, indem du Schlüssel und base URL setzt — das eröffnet nahezu jedes Modell.</p>\n<p><strong>Inspect/Edit wählt keine Elemente aus — warum?</strong>\nDas Artefakt benötigt <code>data-oid</code>-Tags. Bitte den Agent, den Prototyp damit neu zu bauen, und lade dann die Vorschau neu.</p>\n<p><strong>Ist es produktionsreif?</strong>\nEs ist früh dran und iteriert schnell. Für Decks und Lead-Magnet-Seiten ist es bereits großartig; bei komplexen Apps behandle das Ergebnis als starken Entwurf, den du verfeinerst.</p>\n<p><strong>Ist es kostenlos?</strong>\nDie App ist quelloffen unter Apache-2.0 und kostenlos lokal nutzbar. Du zahlst nur für die Modell- und Mediennutzung des jeweiligen Agents und Anbieters, den du verbindest.</p>\n<hr>\n<p><em>Diese geschriebene Anleitung basiert auf dem praxisnahen Test von Sasha (ИИШНЫЙ). Sieh dir oben das vollständige Video an und <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">abonniere ИИШНЫЙ</a> für weitere ehrliche, ungeschnittene Tests von KI-Werkzeugen.</em></p>",
  },
  "fr": {
    title: "Open Design — un premier aperçu honnête (bugs, contournements et configuration avec n'importe quel modèle)",
    summary: "Un premier aperçu sans fard d'Open Design — l'installer, configurer n'importe quel agent, construire un vrai prototype en direct (aspérités comprises), utiliser les outils d'édition/inspection/commentaire sur le canevas, et brancher n'importe quel modèle à moindre coût via un fournisseur compatible OpenAI comme OpenRouter. D'après le test pratique de Sasha (ИИШНЫЙ).",
    bodyHtml: "<p>Ce guide est un premier regard volontairement honnête sur Open Design — ce qui fonctionne d'emblée et les aspérités que vous rencontrerez, montrés en direct plutôt que coupés au montage. Il aborde aussi une astuce vraiment utile : brancher <em>n'importe quel</em> modèle à moindre coût via un fournisseur compatible OpenAI. Il s'appuie sur le test pratique que <strong>Sasha (ИИШНЫЙ)</strong> réalise dans <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">sa démonstration</a>, adapté pour ce guide écrit et mis à jour avec la version actuelle. Regardez la vidéo ci-dessus pour le déroulé en direct, ou poursuivez la lecture pour la version écrite.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/workspace-home.webp\" alt=\"L'espace de travail Open Design — décrivez ce que vous voulez et choisissez un mode.\">\n<em>L'espace de travail Open Design : décrivez ce que vous voulez construire, choisissez un mode, et votre agent fait le reste.</em></p>\n<h2 id=\"what-is-open-design\">Qu'est-ce qu'Open Design ?</h2>\n<p>Open Design est une plateforme de design open source et local-first — une alternative agent-native à Claude Design. Le problème de la « bouillie violette de l'IA » (chaque interface générée se ressemble) est précisément ce que des outils comme celui-ci tentent de résoudre, et la réponse d'Open Design est de <strong>tourner par-dessus l'agent de codage que vous utilisez déjà</strong> plutôt que de livrer son propre modèle. Il détecte Claude Code, Codex, Cursor, Gemini, OpenCode et d'autres sur votre machine et s'en sert comme moteur. Le cadrage de Sasha : il a récolté des dizaines de milliers d'étoiles GitHub dès sa première semaine parce qu'il est gratuit, ouvert et non verrouillé sur un seul fournisseur.</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — clonez-le, lisez-le, auto-hébergez-le.</li>\n<li><strong>Tourne en local</strong> — vos projets sont des dossiers sur votre propre machine.</li>\n<li><strong>N'importe quel agent, n'importe quel modèle</strong> — y compris votre propre clé API via n'importe quel fournisseur compatible OpenAI.</li>\n<li>Une <strong>bibliothèque fournie de compétences de design et de systèmes de design</strong> intégrée.</li>\n<li><strong>Plus que des prototypes</strong> — diaporamas, images, et même de la vidéo.</li>\n</ul>\n<h2 id=\"step-1--install-and-configure\">Étape 1 — Installer et configurer</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Ouvrez l'URL locale qu'il affiche (un port dynamique — ne le codez pas en dur). Vous préférez zéro configuration ? Récupérez l'<strong>application de bureau</strong> sur <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. Au premier lancement, la page des paramètres détecte les CLI d'agent présentes sur votre machine — Sasha utilise Codex — et vous laisse définir un modèle par défaut, ajouter des fournisseurs de médias (MiniMax, OpenAI GPT Image, et d'autres), connecter des sources de données, changer de langue et choisir un thème.</p>\n<h2 id=\"step-2--use-any-model-via-an-openai-compatible-provider\">Étape 2 — Utiliser n'importe quel modèle via un fournisseur compatible OpenAI</h2>\n<p>C'est la pépite la plus utile du test de Sasha. Au-delà des CLI détectées, Open Design vous permet d'<strong>apporter votre propre clé pour n'importe quelle API compatible OpenAI</strong> — ce qui signifie que vous pouvez router via un agrégateur comme OpenRouter et utiliser presque n'importe quel modèle, souvent à moindre coût :</p>\n<ol>\n<li>Chez votre fournisseur, créez une clé API et copiez-la.</li>\n<li>Dans les paramètres d'Open Design, choisissez le type de fournisseur <strong>OpenAI</strong> (OpenRouter et les agrégateurs similaires parlent l'API OpenAI).</li>\n<li>Collez la clé et, point crucial, <strong>changez la base URL</strong> pour le point de terminaison de votre fournisseur (p. ex. la base URL d'OpenRouter), puis choisissez le modèle voulu.</li>\n<li>Enregistrez — la génération passe désormais par ce fournisseur.</li>\n</ol>\n<p>Un piège que rencontre Sasha : la sélection du modèle bascule de manière <strong>globale</strong>, et non par projet ; donc si la génération de médias casse après votre bascule, c'est parce que le fournisseur d'images a suivi le changement de modèle. Définissez explicitement les clés de vos fournisseurs de médias.</p>\n<h2 id=\"step-3--build-a-prototype-rough-edges-and-all\">Étape 3 — Construire un prototype (aspérités comprises)</h2>\n<p>Créez un projet, rédigez votre brief, choisissez <strong>haute fidélité</strong> et envoyez. Open Design exécute d'abord un <strong>formulaire de découverte</strong> — il adapte les questions à votre prompt (plateforme cible, public visé, ton, animation, contraintes), puis un <strong>sélecteur de direction visuelle</strong> (typographie + palette), puis il construit. La sortie est un prototype vivant et interactif doté de contrôles intégrés — l'application générée par Sasha vous laisse activer les animations et changer la couleur d'accent directement sur la page.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/generated-prototype.webp\" alt=\"Un vrai prototype généré dans Open Design.\">\n<em>Un vrai prototype généré, rendu dans l'aperçu — une landing page d'agence sombre et cinématographique.</em></p>\n<p>Réserves honnêtes que Sasha montre à l'écran (et comment les gérer) :</p>\n<ul>\n<li><strong>Il peut choisir par défaut la mauvaise compétence.</strong> S'il commence à construire un « checkpoint/blog » alors que vous vouliez une application mobile, dites-le-lui explicitement : « utilise la compétence mobile-app / front-end ». Définissez la compétence avant de générer.</li>\n<li><strong>Inspect a besoin de balises <code>data-oid</code>.</strong> L'outil Inspect sur le canevas a besoin que l'artefact soit balisé ; s'il dit qu'il ne peut pas sélectionner d'éléments, demandez à l'agent de « reconstruire le prototype avec des balises data-oid », puis rechargez.</li>\n<li><strong>Il est jeune et livre vite.</strong> Attendez-vous à des accrocs occasionnels (navigation qui disparaît après une modification, etc.) — le projet se met à jour presque chaque jour, alors re-tirez souvent.</li>\n</ul>\n<h2 id=\"step-4--the-on-canvas-tools-the-real-draw\">Étape 4 — Les outils sur le canevas (le vrai attrait)</h2>\n<p>Une fois balisée, la boucle d'édition est le point fort. <strong>Inspect</strong> vous laisse survoler n'importe quel élément et ajuster directement couleur, taille et style. <strong>Edit</strong> vous laisse réécrire du texte en ligne (pas d'aller-retour vers le chat pour changer un seul mot). <strong>Comment/picker</strong> vous laisse sélectionner une zone, dessiner et envoyer une note à l'agent (« fais de ce menu un carrousel défilant avec une barre de progression »). C'est cette boucle de retour rapide et visuelle, difficile à reproduire avec un simple agent dans un terminal.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/plugins-hub.webp\" alt=\"Le hub de plugins d'Open Design.\">\n<em>Le hub de plugins : parcourez le registre, importez des plugins et préparez-les pour votre équipe.</em></p>\n<p>Une fois terminé, <strong>Share</strong> exporte en PDF, PPTX, HTML autonome ou markdown — ou déploie sur Vercel en un clic. Le verdict honnête de Sasha : pour des présentations et des pages d'aimant à prospects, c'est déjà un mini-constructeur pratique ; pour le prototypage d'applications/sites complexes, attendez-vous à une vraie itération. Vu qu'il n'a qu'une semaine et se met à jour en permanence, les fondations sont solides.</p>\n<h2 id=\"tips\">Astuces</h2>\n<ul>\n<li><strong>Branchez OpenRouter (ou n'importe quel fournisseur compatible OpenAI)</strong> pour utiliser des modèles moins chers ou différents — pensez à changer la base URL.</li>\n<li><strong>Définissez la compétence explicitement</strong> avant de générer pour qu'il ne choisisse pas par défaut le mauvais modèle.</li>\n<li><strong>Demandez des balises <code>data-oid</code></strong> si Inspect ne peut pas sélectionner d'éléments, puis rechargez.</li>\n<li><strong>Appuyez-vous sur Inspect/Edit/Comment</strong> pour des ajustements visuels rapides plutôt que de relancer un prompt dans le chat.</li>\n<li><strong>Re-tirez souvent</strong> — le projet livre des correctifs presque chaque jour.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Puis-je utiliser un modèle autre que Claude — et payer moins ?</strong>\nOui. Pointez Open Design vers n'importe quelle CLI détectée, ou apportez votre propre clé pour n'importe quel fournisseur compatible OpenAI (p. ex. OpenRouter) en réglant la clé et la base URL — cela ouvre presque n'importe quel modèle.</p>\n<p><strong>Inspect/edit ne sélectionne pas les éléments — pourquoi ?</strong>\nL'artefact a besoin de balises <code>data-oid</code>. Demandez à l'agent de reconstruire le prototype avec, puis rechargez l'aperçu.</p>\n<p><strong>Est-ce prêt pour la production ?</strong>\nC'est tôt et ça itère vite. C'est déjà excellent pour les decks et les pages d'aimant à prospects ; pour des applications complexes, traitez la sortie comme un solide brouillon que vous affinez.</p>\n<p><strong>Est-ce gratuit ?</strong>\nL'application est open source sous Apache-2.0 et gratuite en exécution locale. Vous ne payez que pour l'usage du modèle et des médias de l'agent et du fournisseur que vous connectez.</p>\n<hr>\n<p><em>Ce guide écrit est basé sur le test pratique de Sasha (ИИШНЫЙ). Regardez la vidéo complète ci-dessus, et <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">abonnez-vous à ИИШНЫЙ</a> pour d'autres tests d'outils d'IA honnêtes et non montés.</em></p>",
  },
  "ru": {
    title: "Open Design — честное первое знакомство (баги, обходные пути и настройка любой модели)",
    summary: "Без прикрас первое знакомство с Open Design — установка, настройка любого agent, сборка реального прототипа вживую (со всеми шероховатостями), использование инструментов правки/инспекции/комментирования прямо на холсте и подключение любой модели задёшево через OpenAI-совместимого провайдера вроде OpenRouter. По мотивам практического обзора Саши (ИИШНЫЙ).",
    bodyHtml: "<p>Это руководство — намеренно честное первое знакомство с Open Design: то, что просто работает, и шероховатости, с которыми вы столкнётесь, показаны вживую, а не вырезаны при монтаже. В нём также рассматривается по-настоящему полезный приём: дёшево подключить <em>любую</em> модель через провайдера, совместимого с OpenAI. Оно основано на практическом обзоре, который <strong>Sasha (ИИШНЫЙ)</strong> записывает в <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">своём разборе</a>, адаптировано для этого текстового руководства и обновлено под текущий релиз. Посмотрите видео выше, чтобы увидеть процесс вживую, или читайте дальше текстовую версию.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/workspace-home.webp\" alt=\"Рабочее пространство Open Design — опишите, что вам нужно, и выберите режим.\">\n<em>Рабочее пространство Open Design: опишите, что хотите создать, выберите режим, и ваш agent сделает остальное.</em></p>\n<h2 id=\"what-is-open-design\">Что такое Open Design?</h2>\n<p>Open Design — это платформа для дизайна с открытым исходным кодом и принципом local-first, agent-native альтернатива Claude Design. Проблема «фиолетовой ИИ-кашицы» (когда каждый сгенерированный UI выглядит одинаково) — это именно то, что пытаются решить подобные инструменты, и ответ Open Design в том, чтобы <strong>работать поверх кодового agent, которым вы уже пользуетесь</strong>, а не поставлять собственную модель. Он обнаруживает Claude Code, Codex, Cursor, Gemini, OpenCode и другие на вашей машине и использует их в качестве движка. Формулировка Саши: он собрал десятки тысяч звёзд на GitHub за первую неделю, потому что бесплатен, открыт и не привязан к одному провайдеру.</p>\n<ul>\n<li><strong>Открытый исходный код, Apache-2.0</strong> — клонируйте, читайте, разворачивайте у себя.</li>\n<li><strong>Работает локально</strong> — ваши проекты это папки на вашей собственной машине.</li>\n<li><strong>Любой agent, любая модель</strong> — включая ваш собственный API key через любого OpenAI-совместимого провайдера.</li>\n<li>Встроенная <strong>обширная библиотека дизайн-навыков и дизайн-систем</strong>.</li>\n<li><strong>Не только прототипы</strong> — слайд-деки, изображения, даже видео.</li>\n</ul>\n<h2 id=\"step-1--install-and-configure\">Шаг 1 — Установка и настройка</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Откройте локальный URL, который он выводит (порт динамический — не прописывайте его жёстко). Предпочитаете без настройки? Возьмите <strong>десктоп-приложение</strong> на <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. При первом запуске страница настроек обнаруживает CLI agent на вашей машине — Саша использует Codex — и позволяет задать модель по умолчанию, добавить медиа-провайдеров (MiniMax, OpenAI GPT Image и другие), подключить источники данных, сменить язык и выбрать тему.</p>\n<h2 id=\"step-2--use-any-model-via-an-openai-compatible-provider\">Шаг 2 — Используйте любую модель через OpenAI-совместимого провайдера</h2>\n<p>Это самый полезный самородок в обзоре Саши. Помимо обнаруженных CLI, Open Design позволяет <strong>принести свой собственный key для любого OpenAI-совместимого API</strong> — а значит, вы можете маршрутизировать через агрегатор вроде OpenRouter и использовать почти любую модель, зачастую дешевле:</p>\n<ol>\n<li>У вашего провайдера создайте API key и скопируйте его.</li>\n<li>В настройках Open Design выберите тип провайдера <strong>OpenAI</strong> (OpenRouter и аналогичные агрегаторы говорят на OpenAI API).</li>\n<li>Вставьте key и, что критически важно, <strong>измените base URL</strong> на эндпоинт вашего провайдера (например, base URL OpenRouter), затем выберите нужную модель.</li>\n<li>Сохраните — генерация теперь идёт через этого провайдера.</li>\n</ol>\n<p>Один подводный камень, на который наткнулся Саша: выбор модели переключается <strong>глобально</strong>, а не по проекту, так что если после переключения сломалась генерация медиа — это потому, что провайдер изображений последовал за сменой модели. Задавайте ключи медиа-провайдеров явно.</p>\n<h2 id=\"step-3--build-a-prototype-rough-edges-and-all\">Шаг 3 — Соберите прототип (со всеми шероховатостями)</h2>\n<p>Создайте проект, напишите бриф, выберите <strong>высокую детализацию</strong> и отправьте. Open Design сначала запускает <strong>форму обнаружения</strong> — он подстраивает вопросы под ваш промпт (целевая платформа, для кого, тон, анимация, ограничения), затем <strong>выбор визуального направления</strong> (типографика + палитра), и потом собирает. Результат — живой интерактивный прототип со встроенными элементами управления: в сгенерированном Сашей приложении можно переключать анимацию и менять акцентный цвет прямо на странице.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/generated-prototype.webp\" alt=\"Настоящий прототип, сгенерированный в Open Design.\">\n<em>Настоящий сгенерированный прототип, отрисованный в превью — тёмная, кинематографичная лендинг-страница агентства.</em></p>\n<p>Честные оговорки, которые Саша показывает на камеру (и как с ними быть):</p>\n<ul>\n<li><strong>По умолчанию он может выбрать не тот навык.</strong> Если он начинает строить «checkpoint/blog», когда вам нужно было мобильное приложение, скажите ему явно: «используй навык mobile-app / front-end». Задавайте навык до генерации.</li>\n<li><strong>Inspect требует тегов <code>data-oid</code>.</strong> Инструменту Inspect на холсте нужен размеченный артефакт; если он сообщает, что не может выбрать элементы, попросите agent «пересобрать прототип с тегами data-oid», затем перезагрузите.</li>\n<li><strong>Он молод и выпускается быстро.</strong> Ожидайте редких сбоев (после правки исчезает навигация и т. п.) — проект обновляется почти ежедневно, так что чаще делайте повторный pull.</li>\n</ul>\n<h2 id=\"step-4--the-on-canvas-tools-the-real-draw\">Шаг 4 — Инструменты на холсте (главная изюминка)</h2>\n<p>После разметки цикл редактирования и есть главное достоинство. <strong>Inspect</strong> позволяет навести на любой элемент и напрямую подправить цвет, размер и стиль. <strong>Edit</strong> позволяет переписывать текст прямо на месте (без хождения в чат ради смены одного слова). <strong>Comment/picker</strong> позволяет выделить область, нарисовать и отправить заметку agent («сделай это меню прокручиваемой каруселью с индикатором прогресса»). Это быстрый, визуальный цикл обратной связи, который неудобно воспроизводить с простым agent в терминале.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/plugins-hub.webp\" alt=\"Хаб плагинов Open Design.\">\n<em>Хаб плагинов: просматривайте реестр, импортируйте плагины и готовьте их для своей команды.</em></p>\n<p>Когда закончите, <strong>Share</strong> экспортирует в PDF, PPTX, автономный HTML или markdown — или разворачивает на Vercel в один клик. Честный вердикт Саши: для презентаций и лид-магнит-страниц это уже удобный мини-конструктор; для прототипирования сложных приложений/сайтов ждите реальной итерации. Учитывая, что ему всего неделя и он постоянно обновляется, фундамент крепкий.</p>\n<h2 id=\"tips\">Советы</h2>\n<ul>\n<li><strong>Подключите OpenRouter (или любого OpenAI-совместимого провайдера)</strong>, чтобы использовать более дешёвые или другие модели — не забудьте изменить base URL.</li>\n<li><strong>Задавайте навык явно</strong> перед генерацией, чтобы он не выбрал по умолчанию не тот шаблон.</li>\n<li><strong>Запросите теги <code>data-oid</code></strong>, если Inspect не может выбрать элементы, затем перезагрузите.</li>\n<li><strong>Опирайтесь на Inspect/Edit/Comment</strong> для быстрых визуальных правок вместо повторных промптов в чате.</li>\n<li><strong>Чаще делайте повторный pull</strong> — проект выпускает исправления почти ежедневно.</li>\n</ul>\n<h2 id=\"faq\">Частые вопросы</h2>\n<p><strong>Можно ли использовать модель, отличную от Claude, и платить меньше?</strong>\nДа. Направьте Open Design на любую обнаруженную CLI или принесите свой key для любого OpenAI-совместимого провайдера (например, OpenRouter), задав key и base URL — это открывает почти любую модель.</p>\n<p><strong>Inspect/edit не выбирает элементы — почему?</strong>\nАртефакту нужны теги <code>data-oid</code>. Попросите agent пересобрать прототип с ними, затем перезагрузите превью.</p>\n<p><strong>Готов ли он к продакшену?</strong>\nОн ещё на ранней стадии и быстро развивается. Для деков и лид-магнит-страниц он уже отлично подходит; для сложных приложений относитесь к результату как к крепкому черновику, который вы дорабатываете.</p>\n<p><strong>Он бесплатный?</strong>\nПриложение с открытым исходным кодом под Apache-2.0 и бесплатно для локального запуска. Вы платите только за использование модели и медиа того agent и провайдера, которых подключаете.</p>\n<hr>\n<p><em>Это письменное руководство основано на практическом обзоре Саши (ИИШНЫЙ). Смотрите полное видео выше и <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">подпишитесь на ИИШНЫЙ</a> ради новых честных, несмонтированных тестов ИИ-инструментов.</em></p>",
  },
  "es": {
    title: "Open Design — un primer vistazo honesto (errores, soluciones y configuración con cualquier modelo)",
    summary: "Un primer vistazo sin filtros a Open Design: instalarlo, configurar cualquier agent, construir un prototipo real en vivo (asperezas incluidas), usar las herramientas de editar/inspeccionar/comentar sobre el lienzo y conectar cualquier modelo de forma económica a través de un proveedor compatible con OpenAI como OpenRouter. Basado en la reseña práctica de Sasha (ИИШНЫЙ).",
    bodyHtml: "<p>Esta guía es una primera mirada deliberadamente honesta a Open Design: lo que funciona sin más y las asperezas con las que te toparás, mostradas en vivo en lugar de recortadas. También cubre un truco realmente útil: conectar <em>cualquier</em> modelo de forma económica a través de un proveedor compatible con OpenAI. Sigue la prueba práctica que <strong>Sasha (ИИШНЫЙ)</strong> graba en <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">su recorrido</a>, adaptada para esta guía escrita y actualizada con la versión actual. Mira el video de arriba para ver la ejecución en vivo, o sigue leyendo para la versión escrita.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/workspace-home.webp\" alt=\"El espacio de trabajo de Open Design: describe lo que quieres y elige un modo.\">\n<em>El espacio de trabajo de Open Design: describe lo que quieres construir, elige un modo y tu agent hace el resto.</em></p>\n<h2 id=\"what-is-open-design\">¿Qué es Open Design?</h2>\n<p>Open Design es una plataforma de diseño de código abierto y local-first, una alternativa agent-native a Claude Design. El problema de la «papilla púrpura de la IA» (que toda interfaz generada se vea igual) es justo lo que herramientas como esta intentan resolver, y la respuesta de Open Design es <strong>funcionar sobre el agent de programación que ya usas</strong> en lugar de lanzar su propio modelo. Detecta Claude Code, Codex, Cursor, Gemini, OpenCode y más en tu máquina y lo usa como motor. El planteamiento de Sasha: reunió decenas de miles de estrellas en GitHub en su primera semana porque es gratuito, abierto y no está atado a un solo proveedor.</p>\n<ul>\n<li><strong>Código abierto, Apache-2.0</strong>: clónalo, léelo, autohospédalo.</li>\n<li><strong>Funciona en local</strong>: tus proyectos son carpetas en tu propia máquina.</li>\n<li><strong>Cualquier agent, cualquier modelo</strong>: incluida tu propia API key mediante cualquier proveedor compatible con OpenAI.</li>\n<li>Una <strong>amplia biblioteca de habilidades de diseño y sistemas de diseño</strong> integrada.</li>\n<li><strong>Más que prototipos</strong>: presentaciones, imágenes e incluso video.</li>\n</ul>\n<h2 id=\"step-1--install-and-configure\">Paso 1 — Instalar y configurar</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abre la URL local que imprime (un puerto dinámico: no lo fijes en el código). ¿Prefieres cero configuración? Consigue la <strong>aplicación de escritorio</strong> en <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. En el primer arranque, la página de ajustes detecta las CLI de agent en tu máquina —Sasha usa Codex— y te deja establecer un modelo por defecto, añadir proveedores de medios (MiniMax, OpenAI GPT Image y más), conectar fuentes de datos, cambiar de idioma y elegir un tema.</p>\n<h2 id=\"step-2--use-any-model-via-an-openai-compatible-provider\">Paso 2 — Usa cualquier modelo a través de un proveedor compatible con OpenAI</h2>\n<p>Esta es la perla más útil de la reseña de Sasha. Más allá de las CLI detectadas, Open Design te permite <strong>traer tu propia key para cualquier API compatible con OpenAI</strong>, lo que significa que puedes enrutar a través de un agregador como OpenRouter y usar casi cualquier modelo, a menudo más barato:</p>\n<ol>\n<li>En tu proveedor, crea una API key y cópiala.</li>\n<li>En los ajustes de Open Design, elige el tipo de proveedor <strong>OpenAI</strong> (OpenRouter y agregadores similares hablan la API de OpenAI).</li>\n<li>Pega la key y, fundamental, <strong>cambia la base URL</strong> al endpoint de tu proveedor (p. ej., la base URL de OpenRouter), luego elige el modelo que quieras.</li>\n<li>Guarda: la generación ahora se enruta a través de ese proveedor.</li>\n</ol>\n<p>Un escollo con el que se topa Sasha: la selección de modelo cambia de forma <strong>global</strong>, no por proyecto, así que si la generación de medios se rompe tras el cambio, es porque el proveedor de imágenes siguió al cambio de modelo. Define las keys de tus proveedores de medios de forma explícita.</p>\n<h2 id=\"step-3--build-a-prototype-rough-edges-and-all\">Paso 3 — Construye un prototipo (con asperezas y todo)</h2>\n<p>Crea un proyecto, escribe tu brief, elige <strong>alta fidelidad</strong> y envía. Open Design ejecuta primero un <strong>formulario de descubrimiento</strong> —adapta las preguntas a tu prompt (plataforma objetivo, para quién es, tono, animación, restricciones)—, luego un <strong>selector de dirección visual</strong> (tipografía + paleta) y después construye. La salida es un prototipo vivo e interactivo con controles integrados: la app generada por Sasha te permite alternar las animaciones y cambiar el color de acento directamente en la página.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/generated-prototype.webp\" alt=\"Un prototipo real generado en Open Design.\">\n<em>Un prototipo real generado, renderizado en la vista previa: una landing de agencia oscura y cinematográfica.</em></p>\n<p>Advertencias honestas que Sasha muestra frente a la cámara (y cómo manejarlas):</p>\n<ul>\n<li><strong>Puede elegir por defecto la habilidad equivocada.</strong> Si empieza a construir un «checkpoint/blog» cuando querías una app móvil, díselo explícitamente: «usa la habilidad mobile-app / front-end». Define la habilidad antes de generar.</li>\n<li><strong>Inspect necesita etiquetas <code>data-oid</code>.</strong> La herramienta Inspect del lienzo necesita que el artefacto esté etiquetado; si dice que no puede seleccionar elementos, pídele al agent que «reconstruya el prototipo con etiquetas data-oid» y luego recarga.</li>\n<li><strong>Es joven y publica rápido.</strong> Espera fallos ocasionales (la navegación que desaparece tras una edición, etc.): el proyecto se actualiza casi a diario, así que vuelve a hacer pull con frecuencia.</li>\n</ul>\n<h2 id=\"step-4--the-on-canvas-tools-the-real-draw\">Paso 4 — Las herramientas sobre el lienzo (el verdadero atractivo)</h2>\n<p>Una vez etiquetado, el ciclo de edición es lo más destacado. <strong>Inspect</strong> te permite pasar el cursor sobre cualquier elemento y ajustar color, tamaño y estilo directamente. <strong>Edit</strong> te permite reescribir texto en línea (sin idas y vueltas al chat para cambiar una sola palabra). <strong>Comment/picker</strong> te permite seleccionar un área, dibujar y enviar una nota al agent («convierte este menú en un carrusel con desplazamiento y barra de progreso»). Es ese ciclo de retroalimentación rápido y visual que resulta incómodo de reproducir con un agent simple en una terminal.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/plugins-hub.webp\" alt=\"El hub de plugins de Open Design.\">\n<em>El hub de plugins: explora el registro, importa plugins y prepáralos para tu equipo.</em></p>\n<p>Cuando termines, <strong>Share</strong> exporta a PDF, PPTX, HTML independiente o markdown, o despliega en Vercel con un clic. El veredicto honesto de Sasha: para presentaciones y páginas de captación de leads ya es un práctico mini constructor; para prototipado de apps/sitios complejos, espera una iteración real. Dado que solo tiene una semana y se actualiza constantemente, los cimientos son sólidos.</p>\n<h2 id=\"tips\">Consejos</h2>\n<ul>\n<li><strong>Conecta OpenRouter (o cualquier proveedor compatible con OpenAI)</strong> para usar modelos más baratos o distintos: recuerda cambiar la base URL.</li>\n<li><strong>Define la habilidad explícitamente</strong> antes de generar para que no elija por defecto la plantilla equivocada.</li>\n<li><strong>Pide etiquetas <code>data-oid</code></strong> si Inspect no puede seleccionar elementos, y luego recarga.</li>\n<li><strong>Apóyate en Inspect/Edit/Comment</strong> para ajustes visuales rápidos en lugar de volver a hacer prompt en el chat.</li>\n<li><strong>Vuelve a hacer pull con frecuencia</strong>: el proyecto publica correcciones casi a diario.</li>\n</ul>\n<h2 id=\"faq\">Preguntas frecuentes</h2>\n<p><strong>¿Puedo usar un modelo distinto de Claude y pagar menos?</strong>\nSí. Apunta Open Design a cualquier CLI detectada, o trae tu propia key para cualquier proveedor compatible con OpenAI (p. ej., OpenRouter) configurando la key y la base URL: eso abre casi cualquier modelo.</p>\n<p><strong>Inspect/edit no selecciona elementos, ¿por qué?</strong>\nEl artefacto necesita etiquetas <code>data-oid</code>. Pídele al agent que reconstruya el prototipo con ellas y luego recarga la vista previa.</p>\n<p><strong>¿Está listo para producción?</strong>\nEs temprano y está iterando rápido. Ya es estupendo para decks y páginas de captación de leads; para apps complejas, trata la salida como un borrador sólido que vas refinando.</p>\n<p><strong>¿Es gratis?</strong>\nLa app es de código abierto bajo Apache-2.0 y gratuita para ejecutarse en local. Solo pagas por el uso de modelo y de medios del agent y proveedor que conectes.</p>\n<hr>\n<p><em>Esta guía escrita se basa en la reseña práctica de Sasha (ИИШНЫЙ). Mira el video completo de arriba y <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">suscríbete a ИИШНЫЙ</a> para más pruebas honestas y sin editar de herramientas de IA.</em></p>",
  },
  "pt-br": {
    title: "Open Design — um primeiro olhar honesto (bugs, contornos e configuração com qualquer modelo)",
    summary: "Um primeiro olhar sem maquiagem sobre o Open Design — instalar, configurar qualquer agent, construir um protótipo real ao vivo (com arestas e tudo), usar as ferramentas de editar/inspecionar/comentar sobre o canvas e conectar qualquer modelo de forma barata por meio de um provedor compatível com OpenAI como o OpenRouter. Baseado na análise prática de Sasha (ИИШНЫЙ).",
    bodyHtml: "<p>Este guia é um primeiro olhar deliberadamente honesto sobre o Open Design — as partes que simplesmente funcionam e as arestas com que você vai se deparar, mostradas ao vivo em vez de cortadas na edição. Ele também aborda um truque genuinamente útil: conectar <em>qualquer</em> modelo de forma barata por meio de um provedor compatível com OpenAI. Segue a avaliação prática que <strong>Sasha (ИИШНЫЙ)</strong> grava em <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">seu passo a passo</a>, adaptada para este guia escrito e atualizada com a versão atual. Assista ao vídeo acima para ver a execução ao vivo ou continue lendo a versão escrita.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/workspace-home.webp\" alt=\"O espaço de trabalho do Open Design — descreva o que você quer e escolha um modo.\">\n<em>O espaço de trabalho do Open Design: descreva o que você quer construir, escolha um modo e seu agent faz o resto.</em></p>\n<h2 id=\"what-is-open-design\">O que é o Open Design?</h2>\n<p>O Open Design é uma plataforma de design de código aberto e local-first — uma alternativa agent-native ao Claude Design. O problema do \"mingau roxo da IA\" (toda interface gerada parecer igual) é exatamente o que ferramentas como esta tentam resolver, e a resposta do Open Design é <strong>rodar por cima do agent de programação que você já usa</strong> em vez de entregar um modelo próprio. Ele detecta Claude Code, Codex, Cursor, Gemini, OpenCode e outros na sua máquina e usa isso como motor. O enquadramento de Sasha: ele acumulou dezenas de milhares de estrelas no GitHub na primeira semana porque é gratuito, aberto e não está preso a um único provedor.</p>\n<ul>\n<li><strong>Código aberto, Apache-2.0</strong> — clone, leia, hospede você mesmo.</li>\n<li><strong>Roda localmente</strong> — seus projetos são pastas na sua própria máquina.</li>\n<li><strong>Qualquer agent, qualquer modelo</strong> — incluindo sua própria API key por meio de qualquer provedor compatível com OpenAI.</li>\n<li>Uma <strong>biblioteca robusta de habilidades de design e design systems</strong> embutida.</li>\n<li><strong>Mais do que protótipos</strong> — apresentações de slides, imagens, até vídeo.</li>\n</ul>\n<h2 id=\"step-1--install-and-configure\">Passo 1 — Instalar e configurar</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abra a URL local que ele imprime (uma porta dinâmica — não a fixe no código). Prefere zero configuração? Pegue o <strong>aplicativo desktop</strong> em <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. No primeiro início, a página de configurações detecta as CLIs de agent na sua máquina — Sasha usa o Codex — e permite definir um modelo padrão, adicionar provedores de mídia (MiniMax, OpenAI GPT Image e outros), conectar fontes de dados, trocar de idioma e escolher um tema.</p>\n<h2 id=\"step-2--use-any-model-via-an-openai-compatible-provider\">Passo 2 — Use qualquer modelo via um provedor compatível com OpenAI</h2>\n<p>Esta é a pepita mais útil da análise de Sasha. Além das CLIs detectadas, o Open Design permite que você <strong>traga sua própria key para qualquer API compatível com OpenAI</strong> — o que significa que você pode rotear por um agregador como o OpenRouter e usar quase qualquer modelo, muitas vezes mais barato:</p>\n<ol>\n<li>No seu provedor, crie uma API key e copie-a.</li>\n<li>Nas configurações do Open Design, escolha o tipo de provedor <strong>OpenAI</strong> (OpenRouter e agregadores semelhantes falam a API OpenAI).</li>\n<li>Cole a key e, crucialmente, <strong>altere a base URL</strong> para o endpoint do seu provedor (por exemplo, a base URL do OpenRouter) e então escolha o modelo desejado.</li>\n<li>Salve — a geração agora é roteada por esse provedor.</li>\n</ol>\n<p>Uma pegadinha que Sasha encontra: a seleção de modelo muda de forma <strong>global</strong>, não por projeto, então se a geração de mídia quebrar depois da troca, é porque o provedor de imagens seguiu a troca de modelo. Defina as keys dos seus provedores de mídia explicitamente.</p>\n<h2 id=\"step-3--build-a-prototype-rough-edges-and-all\">Passo 3 — Construa um protótipo (com arestas e tudo)</h2>\n<p>Crie um projeto, escreva seu brief, escolha <strong>alta fidelidade</strong> e envie. O Open Design executa primeiro um <strong>formulário de descoberta</strong> — ele adapta as perguntas ao seu prompt (plataforma alvo, para quem é, tom, animação, restrições), depois um <strong>seletor de direção visual</strong> (tipografia + paleta) e então constrói. A saída é um protótipo vivo e interativo com controles embutidos — o app gerado por Sasha permite alternar animações e trocar a cor de destaque direto na página.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/generated-prototype.webp\" alt=\"Um protótipo real gerado no Open Design.\">\n<em>Um protótipo real gerado, renderizado na pré-visualização — uma landing page de agência escura e cinematográfica.</em></p>\n<p>Ressalvas honestas que Sasha mostra na câmera (e como lidar com elas):</p>\n<ul>\n<li><strong>Ele pode escolher por padrão a habilidade errada.</strong> Se começar a construir um \"checkpoint/blog\" quando você queria um app mobile, diga explicitamente: \"use a habilidade mobile-app / front-end\". Defina a habilidade antes de gerar.</li>\n<li><strong>O Inspect precisa de tags <code>data-oid</code>.</strong> A ferramenta Inspect no canvas precisa do artefato com tags; se ela disser que não consegue selecionar elementos, peça ao agent para \"reconstruir o protótipo com tags data-oid\" e então recarregue.</li>\n<li><strong>Ele é jovem e lança rápido.</strong> Espere falhas ocasionais (a navegação some após uma edição, etc.) — o projeto se atualiza quase diariamente, então faça pull de novo com frequência.</li>\n</ul>\n<h2 id=\"step-4--the-on-canvas-tools-the-real-draw\">Passo 4 — As ferramentas sobre o canvas (o verdadeiro atrativo)</h2>\n<p>Uma vez com tags, o ciclo de edição é o destaque. O <strong>Inspect</strong> permite passar o cursor sobre qualquer elemento e ajustar cor, tamanho e estilo diretamente. O <strong>Edit</strong> permite reescrever texto inline (sem ir e voltar ao chat para mudar uma única palavra). O <strong>Comment/picker</strong> permite selecionar uma área, desenhar e enviar uma nota ao agent (\"transforme este menu em um carrossel com rolagem e barra de progresso\"). É o ciclo de feedback rápido e visual que é desajeitado de reproduzir com um agent simples num terminal.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/plugins-hub.webp\" alt=\"O hub de plugins do Open Design.\">\n<em>O hub de plugins: navegue pelo registro, importe plugins e prepare-os para a sua equipe.</em></p>\n<p>Quando terminar, o <strong>Share</strong> exporta para PDF, PPTX, HTML autônomo ou markdown — ou faz deploy na Vercel com um clique. O veredito honesto de Sasha: para apresentações e páginas de isca digital já é um mini construtor conveniente; para prototipagem de apps/sites complexos, espere iteração de verdade. Considerando que tem apenas uma semana e se atualiza constantemente, a base é sólida.</p>\n<h2 id=\"tips\">Dicas</h2>\n<ul>\n<li><strong>Conecte o OpenRouter (ou qualquer provedor compatível com OpenAI)</strong> para usar modelos mais baratos ou diferentes — lembre-se de alterar a base URL.</li>\n<li><strong>Defina a habilidade explicitamente</strong> antes de gerar para que ele não escolha por padrão o template errado.</li>\n<li><strong>Peça tags <code>data-oid</code></strong> se o Inspect não conseguir selecionar elementos, e então recarregue.</li>\n<li><strong>Apoie-se no Inspect/Edit/Comment</strong> para ajustes visuais rápidos em vez de refazer o prompt no chat.</li>\n<li><strong>Faça pull de novo com frequência</strong> — o projeto lança correções quase diariamente.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Posso usar um modelo diferente do Claude — e pagar menos?</strong>\nSim. Aponte o Open Design para qualquer CLI detectada, ou traga sua própria key para qualquer provedor compatível com OpenAI (por exemplo, OpenRouter) definindo a key e a base URL — isso abre quase qualquer modelo.</p>\n<p><strong>O Inspect/edit não está selecionando elementos — por quê?</strong>\nO artefato precisa de tags <code>data-oid</code>. Peça ao agent para reconstruir o protótipo com elas e então recarregue a pré-visualização.</p>\n<p><strong>Está pronto para produção?</strong>\nÉ cedo e está iterando rápido. Já é ótimo para decks e páginas de isca digital; para apps complexos, trate a saída como um rascunho sólido que você refina.</p>\n<p><strong>É gratuito?</strong>\nO app é de código aberto sob Apache-2.0 e gratuito para rodar localmente. Você só paga pelo uso de modelo e de mídia do agent e do provedor que você conectar.</p>\n<hr>\n<p><em>Este guia escrito é baseado na análise prática de Sasha (ИИШНЫЙ). Assista ao vídeo completo acima e <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">inscreva-se no ИИШНЫЙ</a> para mais testes honestos e sem edição de ferramentas de IA.</em></p>",
  },
  "it": {
    title: "Open Design — un primo sguardo onesto (bug, soluzioni e configurazione con qualsiasi modello)",
    summary: "Un primo sguardo senza filtri a Open Design: installarlo, configurare qualsiasi agent, costruire un prototipo reale dal vivo (spigoli inclusi), usare gli strumenti di modifica/ispezione/commento direttamente sulla tela e collegare qualsiasi modello a basso costo tramite un provider compatibile con OpenAI come OpenRouter. Basato sulla recensione pratica di Sasha (ИИШНЫЙ).",
    bodyHtml: "<p>Questa guida è uno sguardo volutamente onesto a Open Design: le parti che funzionano subito e le spigolature in cui ti imbatterai, mostrate dal vivo anziché tagliate in fase di montaggio. Affronta anche un trucco davvero utile: collegare <em>qualsiasi</em> modello a basso costo tramite un provider compatibile con OpenAI. Si basa sulla prova pratica che <strong>Sasha (ИИШНЫЙ)</strong> registra nella <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">sua guida video</a>, adattata per questa guida scritta e aggiornata alla versione attuale. Guarda il video qui sopra per la prova dal vivo, oppure continua a leggere per la versione scritta.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/workspace-home.webp\" alt=\"L'area di lavoro di Open Design — descrivi ciò che vuoi e scegli una modalità.\">\n<em>L'area di lavoro di Open Design: descrivi ciò che vuoi costruire, scegli una modalità e il tuo agent fa il resto.</em></p>\n<h2 id=\"what-is-open-design\">Che cos'è Open Design?</h2>\n<p>Open Design è una piattaforma di design open source e local-first — un'alternativa agent-native a Claude Design. Il problema della «pappa viola dell'IA» (ogni UI generata che si somiglia) è esattamente ciò che strumenti come questo cercano di risolvere, e la risposta di Open Design è <strong>girare sopra l'agent di programmazione che già usi</strong> invece di proporre un modello proprio. Rileva Claude Code, Codex, Cursor, Gemini, OpenCode e altri sulla tua macchina e li usa come motore. L'inquadramento di Sasha: ha raccolto decine di migliaia di stelle su GitHub nella prima settimana perché è gratuito, aperto e non vincolato a un singolo provider.</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — clonalo, leggilo, ospitalo in self-hosting.</li>\n<li><strong>Gira in locale</strong> — i tuoi progetti sono cartelle sulla tua macchina.</li>\n<li><strong>Qualsiasi agent, qualsiasi modello</strong> — inclusa la tua API key tramite qualsiasi provider compatibile con OpenAI.</li>\n<li>Una <strong>ricca libreria di competenze di design e design system</strong> integrata.</li>\n<li><strong>Più dei prototipi</strong> — presentazioni, immagini, persino video.</li>\n</ul>\n<h2 id=\"step-1--install-and-configure\">Passo 1 — Installare e configurare</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Apri l'URL locale che stampa (una porta dinamica — non scriverla fissa nel codice). Preferisci zero configurazione? Scarica l'<strong>app desktop</strong> da <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. Al primo avvio la pagina delle impostazioni rileva le CLI degli agent sulla tua macchina — Sasha usa Codex — e ti permette di impostare un modello predefinito, aggiungere provider di media (MiniMax, OpenAI GPT Image e altri), collegare fonti dati, cambiare lingua e scegliere un tema.</p>\n<h2 id=\"step-2--use-any-model-via-an-openai-compatible-provider\">Passo 2 — Usa qualsiasi modello tramite un provider compatibile con OpenAI</h2>\n<p>Questa è la pepita più utile della recensione di Sasha. Oltre alle CLI rilevate, Open Design ti permette di <strong>portare la tua key per qualsiasi API compatibile con OpenAI</strong> — il che significa che puoi instradare tramite un aggregatore come OpenRouter e usare quasi qualsiasi modello, spesso a costo inferiore:</p>\n<ol>\n<li>Presso il tuo provider, crea una API key e copiala.</li>\n<li>Nelle impostazioni di Open Design, scegli il tipo di provider <strong>OpenAI</strong> (OpenRouter e aggregatori simili parlano l'API OpenAI).</li>\n<li>Incolla la key e, fondamentale, <strong>cambia la base URL</strong> con l'endpoint del tuo provider (ad es. la base URL di OpenRouter), poi scegli il modello desiderato.</li>\n<li>Salva — la generazione ora viene instradata tramite quel provider.</li>\n</ol>\n<p>Un inghippo in cui incappa Sasha: la selezione del modello cambia in modo <strong>globale</strong>, non per progetto, quindi se la generazione di media si rompe dopo il cambio, è perché il provider di immagini ha seguito il cambio di modello. Imposta in modo esplicito le key dei tuoi provider di media.</p>\n<h2 id=\"step-3--build-a-prototype-rough-edges-and-all\">Passo 3 — Costruisci un prototipo (spigoli inclusi)</h2>\n<p>Crea un progetto, scrivi il tuo brief, scegli <strong>alta fedeltà</strong> e invia. Open Design esegue prima un <strong>modulo di scoperta</strong> — adatta le domande al tuo prompt (piattaforma di destinazione, per chi è, tono, animazione, vincoli), poi un <strong>selettore di direzione visiva</strong> (tipografia + palette), quindi costruisce. L'output è un prototipo vivo e interattivo con controlli integrati — l'app generata da Sasha ti permette di attivare le animazioni e cambiare il colore d'accento direttamente sulla pagina.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/generated-prototype.webp\" alt=\"Un vero prototipo generato in Open Design.\">\n<em>Un vero prototipo generato, renderizzato nell'anteprima — una landing page di agenzia scura e cinematografica.</em></p>\n<p>Avvertenze oneste che Sasha mostra davanti alla telecamera (e come gestirle):</p>\n<ul>\n<li><strong>Potrebbe scegliere di default la competenza sbagliata.</strong> Se inizia a costruire un «checkpoint/blog» quando volevi un'app mobile, diglielo esplicitamente: «usa la competenza mobile-app / front-end». Imposta la competenza prima di generare.</li>\n<li><strong>Inspect ha bisogno dei tag <code>data-oid</code>.</strong> Lo strumento Inspect sulla tela richiede che l'artefatto sia taggato; se dice che non riesce a selezionare gli elementi, chiedi all'agent di «ricostruire il prototipo con i tag data-oid», poi ricarica.</li>\n<li><strong>È giovane e rilascia in fretta.</strong> Aspettati glitch occasionali (la navigazione che scompare dopo una modifica, ecc.) — il progetto si aggiorna quasi ogni giorno, quindi rifai il pull spesso.</li>\n</ul>\n<h2 id=\"step-4--the-on-canvas-tools-the-real-draw\">Passo 4 — Gli strumenti sulla tela (il vero richiamo)</h2>\n<p>Una volta taggato, il ciclo di modifica è il punto forte. <strong>Inspect</strong> ti permette di passare sopra qualsiasi elemento e regolare direttamente colore, dimensione e stile. <strong>Edit</strong> ti permette di riscrivere il testo inline (niente andirivieni con la chat per cambiare una sola parola). <strong>Comment/picker</strong> ti permette di selezionare un'area, disegnare e inviare una nota all'agent («trasforma questo menu in un carosello scorrevole con una barra di avanzamento»). È il ciclo di feedback rapido e visivo che è scomodo da riprodurre con un semplice agent in un terminale.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/plugins-hub.webp\" alt=\"L'hub dei plugin di Open Design.\">\n<em>L'hub dei plugin: sfoglia il registro, importa i plugin e preparali per il tuo team.</em></p>\n<p>Quando hai finito, <strong>Share</strong> esporta in PDF, PPTX, HTML autonomo o markdown — oppure fa il deploy su Vercel con un clic. Il verdetto onesto di Sasha: per presentazioni e pagine lead-magnet è già un comodo mini-builder; per la prototipazione di app/siti complessi aspettati una vera iterazione. Dato che ha solo una settimana e si aggiorna di continuo, le fondamenta sono solide.</p>\n<h2 id=\"tips\">Consigli</h2>\n<ul>\n<li><strong>Collega OpenRouter (o qualsiasi provider compatibile con OpenAI)</strong> per usare modelli più economici o diversi — ricordati di cambiare la base URL.</li>\n<li><strong>Imposta la competenza in modo esplicito</strong> prima di generare, così non sceglie di default il template sbagliato.</li>\n<li><strong>Richiedi i tag <code>data-oid</code></strong> se Inspect non riesce a selezionare gli elementi, poi ricarica.</li>\n<li><strong>Affidati a Inspect/Edit/Comment</strong> per ritocchi visivi rapidi invece di rifare il prompt in chat.</li>\n<li><strong>Rifai il pull spesso</strong> — il progetto rilascia correzioni quasi ogni giorno.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Posso usare un modello diverso da Claude — e pagare meno?</strong>\nSì. Punta Open Design verso qualsiasi CLI rilevata, oppure porta la tua key per qualsiasi provider compatibile con OpenAI (ad es. OpenRouter) impostando la key e la base URL — questo apre quasi qualsiasi modello.</p>\n<p><strong>Inspect/edit non seleziona gli elementi — perché?</strong>\nL'artefatto ha bisogno dei tag <code>data-oid</code>. Chiedi all'agent di ricostruire il prototipo con essi, poi ricarica l'anteprima.</p>\n<p><strong>È pronto per la produzione?</strong>\nÈ agli inizi e itera in fretta. È già ottimo per deck e pagine lead-magnet; per app complesse, tratta l'output come una solida bozza che affini.</p>\n<p><strong>È gratuito?</strong>\nL'app è open source sotto Apache-2.0 e gratuita da eseguire in locale. Paghi solo per l'uso del modello e dei media dell'agent e del provider che colleghi.</p>\n<hr>\n<p><em>Questa guida scritta si basa sulla recensione pratica di Sasha (ИИШНЫЙ). Guarda il video completo qui sopra e <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">iscriviti a ИИШНЫЙ</a> per altri test onesti e non montati di strumenti di IA.</em></p>",
  },
  "tr": {
    title: "Open Design — dürüst bir ilk bakış (hatalar, çözümler ve herhangi bir modelle kurulum)",
    summary: "Open Design'a allayıp pullamadan bir ilk bakış — kur, herhangi bir agent'ı yapılandır, canlı olarak gerçek bir prototip oluştur (pürüzleriyle birlikte), tuval üzerindeki düzenle/incele/yorumla araçlarını kullan ve OpenRouter gibi OpenAI uyumlu bir sağlayıcı üzerinden herhangi bir modeli ucuza bağla. Sasha (ИИШНЫЙ)'nin uygulamalı incelemesine dayanır.",
    bodyHtml: "<p>Bu rehber, Open Design'a bilinçli olarak dürüst bir ilk bakış sunuyor — sorunsuz çalışan kısımlar ve karşılaşacağın pürüzler, kurguda gizlenmek yerine canlı olarak gösteriliyor. Ayrıca gerçekten işe yarar bir püf noktasını da ele alıyor: <em>herhangi bir</em> modeli OpenAI uyumlu bir sağlayıcı üzerinden ucuza bağlamak. <strong>Sasha (ИИШНЫЙ)</strong>'nin <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">tanıtım videosunda</a> kaydettiği uygulamalı incelemeyi temel alıyor; bu yazılı rehber için uyarlandı ve güncel sürüme göre güncellendi. Canlı çalışmayı görmek için yukarıdaki videoyu izle ya da yazılı sürüm için okumaya devam et.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/workspace-home.webp\" alt=\"Open Design çalışma alanı — ne istediğinizi tarif edin ve bir mod seçin.\">\n<em>Open Design çalışma alanı: ne oluşturmak istediğinizi tarif edin, bir mod seçin, gerisini agent'ınız halletsin.</em></p>\n<h2 id=\"what-is-open-design\">Open Design nedir?</h2>\n<p>Open Design, açık kaynaklı ve local-first bir tasarım platformudur — Claude Design'a agent-native bir alternatif. \"Yapay zeka mor lapası\" sorunu (üretilen her arayüzün aynı görünmesi) tam da bu tür araçların çözmeye çalıştığı şeydir ve Open Design'ın yanıtı, kendi modelini sunmak yerine <strong>zaten kullandığınız kodlama agent'ının üzerinde çalışmaktır</strong>. Makinenizdeki Claude Code, Codex, Cursor, Gemini, OpenCode ve daha fazlasını algılar ve bunu motor olarak kullanır. Sasha'nın çerçevelemesi: ücretsiz, açık ve tek bir sağlayıcıya kilitli olmadığı için ilk haftasında on binlerce GitHub yıldızı topladı.</p>\n<ul>\n<li><strong>Açık kaynak, Apache-2.0</strong> — klonlayın, okuyun, kendiniz barındırın.</li>\n<li><strong>Yerelde çalışır</strong> — projeleriniz kendi makinenizdeki klasörlerdir.</li>\n<li><strong>Herhangi bir agent, herhangi bir model</strong> — herhangi bir OpenAI uyumlu sağlayıcı aracılığıyla kendi API key'iniz dahil.</li>\n<li>Yerleşik <strong>zengin bir tasarım becerileri ve tasarım sistemleri kütüphanesi</strong>.</li>\n<li><strong>Prototiplerden fazlası</strong> — sunum desteleri, görseller, hatta video.</li>\n</ul>\n<h2 id=\"step-1--install-and-configure\">Adım 1 — Kurun ve yapılandırın</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Yazdırdığı yerel URL'yi açın (dinamik bir port — sabit kodlamayın). Sıfır kurulum mu tercih edersiniz? <a href=\"https://open-design.ai/download\">open-design.ai/download</a> adresinden <strong>masaüstü uygulamasını</strong> indirin. İlk açılışta ayarlar sayfası makinenizdeki agent CLI'larını algılar — Sasha Codex kullanıyor — ve varsayılan bir model belirlemenize, medya sağlayıcıları (MiniMax, OpenAI GPT Image ve daha fazlası) eklemenize, veri kaynaklarına bağlanmanıza, dil değiştirmenize ve bir tema seçmenize olanak tanır.</p>\n<h2 id=\"step-2--use-any-model-via-an-openai-compatible-provider\">Adım 2 — OpenAI uyumlu bir sağlayıcı üzerinden herhangi bir modeli kullanın</h2>\n<p>Bu, Sasha'nın incelemesindeki en faydalı parça. Algılanan CLI'ların ötesinde, Open Design <strong>herhangi bir OpenAI uyumlu API için kendi key'inizi getirmenize</strong> izin verir — yani OpenRouter gibi bir toplayıcı üzerinden yönlendirip neredeyse her modeli, çoğu zaman daha ucuza kullanabilirsiniz:</p>\n<ol>\n<li>Sağlayıcınızda bir API key oluşturun ve kopyalayın.</li>\n<li>Open Design ayarlarında <strong>OpenAI</strong> sağlayıcı türünü seçin (OpenRouter ve benzeri toplayıcılar OpenAI API'sini konuşur).</li>\n<li>Key'i yapıştırın ve en önemlisi <strong>base URL'yi değiştirip</strong> sağlayıcınızın uç noktasına ayarlayın (örn. OpenRouter base URL'si), ardından istediğiniz modeli seçin.</li>\n<li>Kaydedin — üretim artık o sağlayıcı üzerinden yönlendirilir.</li>\n</ol>\n<p>Sasha'nın takıldığı bir tuzak: model seçimi proje bazında değil, <strong>global</strong> olarak değişir; dolayısıyla geçişten sonra medya üretimi bozulursa, bunun nedeni görsel sağlayıcının model değişimini izlemesidir. Medya sağlayıcı key'lerinizi açıkça ayarlayın.</p>\n<h2 id=\"step-3--build-a-prototype-rough-edges-and-all\">Adım 3 — Bir prototip oluşturun (pürüzleriyle birlikte)</h2>\n<p>Bir proje oluşturun, brief'inizi yazın, <strong>yüksek doğrulukta</strong> seçeneğini seçin ve gönderin. Open Design önce bir <strong>keşif formu</strong> çalıştırır — soruları prompt'unuza göre uyarlar (hedef platform, kimin için, ton, animasyon, kısıtlamalar), ardından bir <strong>görsel yön seçici</strong> (tipografi + palet) ve sonra inşa eder. Çıktı, yerleşik kontrollere sahip canlı, etkileşimli bir prototiptir — Sasha'nın ürettiği uygulama, animasyonları açıp kapatmanıza ve vurgu rengini doğrudan sayfada değiştirmenize izin verir.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/generated-prototype.webp\" alt=\"Open Design'da üretilmiş gerçek bir prototip.\">\n<em>Önizlemede oluşturulan gerçek bir üretilmiş prototip — karanlık, sinematik bir ajans açılış sayfası.</em></p>\n<p>Sasha'nın kamera karşısında gösterdiği dürüst uyarılar (ve bunlarla nasıl başa çıkılacağı):</p>\n<ul>\n<li><strong>Varsayılan olarak yanlış beceriyi seçebilir.</strong> Siz bir mobil uygulama isterken \"checkpoint/blog\" oluşturmaya başlarsa, ona açıkça söyleyin: \"mobile-app / front-end becerisini kullan.\" Üretmeden önce beceriyi ayarlayın.</li>\n<li><strong>Inspect, <code>data-oid</code> etiketlerine ihtiyaç duyar.</strong> Tuvaldeki Inspect aracı, yapıtın etiketlenmiş olmasını gerektirir; öğeleri seçemediğini söylüyorsa, agent'tan \"prototipi data-oid etiketleriyle yeniden oluşturmasını\" isteyin, ardından yeniden yükleyin.</li>\n<li><strong>Genç ve hızlı sürüm çıkarıyor.</strong> Zaman zaman aksaklıklar bekleyin (bir düzenlemeden sonra gezinmenin kaybolması vb.) — proje neredeyse her gün güncelleniyor, bu yüzden sık sık yeniden pull yapın.</li>\n</ul>\n<h2 id=\"step-4--the-on-canvas-tools-the-real-draw\">Adım 4 — Tuval üzerindeki araçlar (asıl cazibe)</h2>\n<p>Etiketlendikten sonra, düzenleme döngüsü öne çıkan unsurdur. <strong>Inspect</strong>, herhangi bir öğenin üzerine gelip rengi, boyutu ve stili doğrudan ayarlamanıza olanak tanır. <strong>Edit</strong>, metni satır içinde yeniden yazmanıza olanak tanır (tek bir kelimeyi değiştirmek için sohbete gidip gelmek yok). <strong>Comment/picker</strong>, bir alan seçmenize, çizim yapmanıza ve agent'a bir not göndermenize olanak tanır (\"bu menüyü ilerleme çubuğu olan kaydırmalı bir karusele dönüştür\"). Bu, bir terminaldeki sade bir agent ile yeniden üretilmesi zahmetli olan hızlı, görsel geri bildirim döngüsüdür.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-first-look-community/plugins-hub.webp\" alt=\"Open Design eklenti merkezi.\">\n<em>Eklenti merkezi: kayıt defterine göz atın, eklentileri içe aktarın ve ekibiniz için hazırlayın.</em></p>\n<p>İşiniz bittiğinde <strong>Share</strong>, PDF, PPTX, bağımsız HTML veya markdown olarak dışa aktarır — ya da tek tıkla Vercel'e dağıtır. Sasha'nın dürüst hükmü: sunumlar ve lead-magnet sayfaları için zaten kullanışlı bir mini oluşturucu; karmaşık uygulama/site prototiplemesi için gerçek bir yineleme bekleyin. Yalnızca bir haftalık olduğu ve sürekli güncellendiği düşünülürse, temeli sağlam.</p>\n<h2 id=\"tips\">İpuçları</h2>\n<ul>\n<li>Daha ucuz veya farklı modelleri kullanmak için <strong>OpenRouter'ı (ya da herhangi bir OpenAI uyumlu sağlayıcıyı) bağlayın</strong> — base URL'yi değiştirmeyi unutmayın.</li>\n<li>Yanlış şablonu varsayılan olarak seçmemesi için üretmeden önce <strong>beceriyi açıkça ayarlayın</strong>.</li>\n<li>Inspect öğeleri seçemiyorsa <strong><code>data-oid</code> etiketleri isteyin</strong>, ardından yeniden yükleyin.</li>\n<li>Sohbette yeniden prompt yazmak yerine hızlı görsel ince ayarlar için <strong>Inspect/Edit/Comment'e yaslanın</strong>.</li>\n<li><strong>Sık sık yeniden pull yapın</strong> — proje neredeyse her gün düzeltmeler yayınlıyor.</li>\n</ul>\n<h2 id=\"faq\">SSS</h2>\n<p><strong>Claude dışında bir model kullanıp daha az ödeyebilir miyim?</strong>\nEvet. Open Design'ı algılanan herhangi bir CLI'ya yönlendirin ya da key ve base URL'yi ayarlayarak herhangi bir OpenAI uyumlu sağlayıcı (örn. OpenRouter) için kendi key'inizi getirin — bu, neredeyse her modeli açar.</p>\n<p><strong>Inspect/edit öğeleri seçmiyor — neden?</strong>\nYapıtın <code>data-oid</code> etiketlerine ihtiyacı var. Agent'tan prototipi bunlarla yeniden oluşturmasını isteyin, ardından önizlemeyi yeniden yükleyin.</p>\n<p><strong>Üretime hazır mı?</strong>\nHenüz erken ve hızla yineleniyor. Desteler ve lead-magnet sayfaları için zaten harika; karmaşık uygulamalar için çıktıyı, üzerinde çalışıp inceltdiğiniz sağlam bir taslak olarak değerlendirin.</p>\n<p><strong>Ücretsiz mi?</strong>\nUygulama Apache-2.0 altında açık kaynaktır ve yerelde çalıştırması ücretsizdir. Yalnızca bağladığınız agent ve sağlayıcının model ve medya kullanımı için ödeme yaparsınız.</p>\n<hr>\n<p><em>Bu yazılı kılavuz, Sasha (ИИШНЫЙ)'nin uygulamalı incelemesine dayanır. Yukarıdaki tam videoyu izleyin ve daha fazla dürüst, montajsız yapay zeka aracı testi için <a href=\"https://www.youtube.com/watch?v=lgwFdKAyaMM\">ИИШНЫЙ'a abone olun</a>.</em></p>",
  },
};
